{
  "name": "SAFE-VOICE",
  "description": "A mission-critical women's safety application with voice-triggered SOS, real-time location sharing, and emergency contact integration.",
  "requestFramePermissions": [
    "microphone",
    "geolocation"
  ]
}

export interface UserProfile {
  userId: string;
  name: string;
  email: string;
  phone: string;
  emergencyKeyword: string;
  isArmed: boolean;
  createdAt: number;
}

export interface Contact {
  contactId: string;
  userId: string;
  name: string;
  phone: string;
  relationship: string;
}

export enum EmergencyStatus {
  ACTIVE = 'ACTIVE',
  SAFE = 'SAFE'
}

export interface EmergencyRecord {
  emergencyId: string;
  userId: string;
  status: EmergencyStatus;
  triggeredAt: number;
  resolvedAt?: number;
}

export interface LocationUpdate {
  emergencyId: string;
  latitude: number;
  longitude: number;
  timestamp: number;
}

export type AppState = 'SPLASH' | 'AUTH' | 'HOME' | 'EMERGENCY' | 'SETTINGS' | 'TRUSTED_VIEW';

import { UserProfile, Contact, EmergencyRecord, LocationUpdate, EmergencyStatus } from './types';

/**
 * MOCK FIREBASE SERVICE
 * In a real production environment, this would use the firebase SDK.
 * This implementation provides real-time persistence behavior for hackathon demonstration.
 */

const STORAGE_KEY = 'SAFE_VOICE_DB';

const getDB = () => JSON.parse(localStorage.getItem(STORAGE_KEY) || '{"users":{}, "contacts":[], "emergencies":[], "locations":[]}');
const saveDB = (db: any) => localStorage.setItem(STORAGE_KEY, JSON.stringify(db));

export const firebaseService = {
  // AUTH
  getCurrentUser: (): UserProfile | null => {
    const userJson = localStorage.getItem('SAFE_VOICE_SESSION');
    return userJson ? JSON.parse(userJson) : null;
  },

  login: async (email: string): Promise<UserProfile> => {
    const db = getDB();
    let user = Object.values(db.users).find((u: any) => u.email === email) as UserProfile;
    if (!user) {
      user = {
        userId: 'u_' + Math.random().toString(36).substr(2, 9),
        name: 'Demo User',
        email,
        phone: '+15550123',
        emergencyKeyword: 'HELP',
        isArmed: false,
        createdAt: Date.now()
      };
      db.users[user.userId] = user;
      saveDB(db);
    }
    localStorage.setItem('SAFE_VOICE_SESSION', JSON.stringify(user));
    return user;
  },

  logout: () => {
    localStorage.removeItem('SAFE_VOICE_SESSION');
  },

  updateProfile: (userId: string, updates: Partial<UserProfile>) => {
    const db = getDB();
    if (db.users[userId]) {
      db.users[userId] = { ...db.users[userId], ...updates };
      saveDB(db);
      localStorage.setItem('SAFE_VOICE_SESSION', JSON.stringify(db.users[userId]));
    }
  },

  // CONTACTS
  getContacts: (userId: string): Contact[] => {
    return getDB().contacts.filter((c: Contact) => c.userId === userId);
  },

  addContact: (contact: Contact) => {
    const db = getDB();
    db.contacts.push(contact);
    saveDB(db);
  },

  deleteContact: (contactId: string) => {
    const db = getDB();
    db.contacts = db.contacts.filter((c: Contact) => c.contactId !== contactId);
    saveDB(db);
  },

  // EMERGENCY
  triggerEmergency: (userId: string): string => {
    const db = getDB();
    const emergencyId = 'e_' + Date.now();
    const record: EmergencyRecord = {
      emergencyId,
      userId,
      status: EmergencyStatus.ACTIVE,
      triggeredAt: Date.now()
    };
    db.emergencies.push(record);
    saveDB(db);
    return emergencyId;
  },

  resolveEmergency: (emergencyId: string) => {
    const db = getDB();
    const record = db.emergencies.find((e: EmergencyRecord) => e.emergencyId === emergencyId);
    if (record) {
      record.status = EmergencyStatus.SAFE;
      record.resolvedAt = Date.now();
      saveDB(db);
    }
  },

  getActiveEmergency: (userId: string): EmergencyRecord | undefined => {
    return getDB().emergencies.find((e: EmergencyRecord) => e.userId === userId && e.status === EmergencyStatus.ACTIVE);
  },

  // LOCATIONS
  pushLocation: (location: LocationUpdate) => {
    const db = getDB();
    db.locations.push(location);
    saveDB(db);
  },

  getEmergencyLocations: (emergencyId: string): LocationUpdate[] => {
    return getDB().locations.filter((l: LocationUpdate) => l.emergencyId === emergencyId);
  }
};

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { UserProfile, AppState, EmergencyRecord, EmergencyStatus } from './types';
import { firebaseService } from './firebase';
import SplashScreen from './screens/SplashScreen';
import AuthScreen from './screens/AuthScreen';
import HomeScreen from './screens/HomeScreen';
import EmergencyScreen from './screens/EmergencyScreen';
import SettingsScreen from './screens/SettingsScreen';
import TrustedContactView from './screens/TrustedContactView';

const App: React.FC = () => {
  const [currentScreen, setCurrentScreen] = useState<AppState>('SPLASH');
  const [user, setUser] = useState<UserProfile | null>(null);
  const [activeEmergency, setActiveEmergency] = useState<EmergencyRecord | null>(null);

  // App initialization
  useEffect(() => {
    const timer = setTimeout(() => {
      const savedUser = firebaseService.getCurrentUser();
      if (savedUser) {
        setUser(savedUser);
        const emergency = firebaseService.getActiveEmergency(savedUser.userId);
        if (emergency) {
          setActiveEmergency(emergency);
          setCurrentScreen('EMERGENCY');
        } else {
          setCurrentScreen('HOME');
        }
      } else {
        setCurrentScreen('AUTH');
      }
    }, 2500); // Realistic splash delay
    return () => clearTimeout(timer);
  }, []);

  const handleLogin = (userData: UserProfile) => {
    setUser(userData);
    setCurrentScreen('HOME');
  };

  const handleLogout = () => {
    firebaseService.logout();
    setUser(null);
    setCurrentScreen('AUTH');
  };

  const triggerSOS = useCallback(() => {
    if (!user) return;
    const emergencyId = firebaseService.triggerEmergency(user.userId);
    const emergency = {
      emergencyId,
      userId: user.userId,
      status: EmergencyStatus.ACTIVE,
      triggeredAt: Date.now()
    };
    setActiveEmergency(emergency);
    setCurrentScreen('EMERGENCY');
  }, [user]);

  const resolveEmergency = () => {
    if (activeEmergency) {
      firebaseService.resolveEmergency(activeEmergency.emergencyId);
      setActiveEmergency(null);
      setCurrentScreen('HOME');
    }
  };

  return (
    <div className="flex flex-col h-screen max-w-md mx-auto relative overflow-hidden bg-[#0F1115]">
      {currentScreen === 'SPLASH' && <SplashScreen />}

      {currentScreen === 'AUTH' && (
        <AuthScreen onLogin={handleLogin} />
      )}

      {currentScreen === 'HOME' && user && (
        <HomeScreen 
          user={user} 
          onLogout={handleLogout}
          onTriggerSOS={triggerSOS}
          onSettings={() => setCurrentScreen('SETTINGS')}
          onTrustedView={() => setCurrentScreen('TRUSTED_VIEW')}
          refreshUser={() => setUser(firebaseService.getCurrentUser())}
        />
      )}

      {currentScreen === 'SETTINGS' && user && (
        <SettingsScreen 
          user={user} 
          onBack={() => setCurrentScreen('HOME')}
          refreshUser={() => setUser(firebaseService.getCurrentUser())}
        />
      )}

      {currentScreen === 'EMERGENCY' && user && activeEmergency && (
        <EmergencyScreen 
          user={user} 
          emergency={activeEmergency}
          onResolve={resolveEmergency}
        />
      )}

      {currentScreen === 'TRUSTED_VIEW' && (
        <TrustedContactView onBack={() => setCurrentScreen('HOME')} />
      )}
    </div>
  );
};

export default App;

