import React, { useState } from 'react';
import { firebaseService } from '../firebase';
import { UserProfile } from '../types';

interface AuthScreenProps {
  onLogin: (user: UserProfile) => void;
}

const AuthScreen: React.FC<AuthScreenProps> = ({ onLogin }) => {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [loading, setLoading] = useState(false);
  const [isSignup, setIsSignup] = useState(false);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!email || !password) return;

    setLoading(true);
    // Simulate network delay
    setTimeout(async () => {
      try {
        const user = await firebaseService.login(email);
        onLogin(user);
      } catch (err) {
        alert("Authentication failed. Please try again.");
      } finally {
        setLoading(false);
      }
    }, 1000);
  };

  return (
    <div className="flex flex-col h-full w-full p-8 bg-[#0F1115]">
      <div className="mt-12 mb-12">
        <h2 className="text-3xl font-bold text-white mb-2">{isSignup ? 'Create Account' : 'Welcome Back'}</h2>
        <p className="text-gray-400">Join the safety network.</p>
      </div>

      <form onSubmit={handleSubmit} className="flex flex-col gap-4">
        <div className="flex flex-col gap-1">
          <label className="text-xs text-gray-500 uppercase font-bold tracking-wider">Email Address</label>
          <input 
            type="email"
            value={email}
            onChange={(e) => setEmail(e.target.value)}
            className="w-full bg-[#1A1D24] border border-gray-800 rounded-xl p-4 text-white focus:outline-none focus:border-[#D32F2F]"
            placeholder="name@example.com"
            required
          />
        </div>

        <div className="flex flex-col gap-1">
          <label className="text-xs text-gray-500 uppercase font-bold tracking-wider">Password</label>
          <input 
            type="password"
            value={password}
            onChange={(e) => setPassword(e.target.value)}
            className="w-full bg-[#1A1D24] border border-gray-800 rounded-xl p-4 text-white focus:outline-none focus:border-[#D32F2F]"
            placeholder="••••••••"
            required
          />
        </div>

        <button 
          type="submit"
          disabled={loading}
          className={`w-full ${loading ? 'bg-gray-700' : 'bg-[#D32F2F]'} text-white font-bold py-4 rounded-xl mt-4 transition-all active:scale-95`}
        >
          {loading ? 'Processing...' : (isSignup ? 'Register' : 'Secure Login')}
        </button>
      </form>

      <div className="mt-auto flex flex-col items-center gap-4">
        <button 
          onClick={() => setIsSignup(!isSignup)}
          className="text-gray-400 text-sm hover:text-white transition-colors"
        >
          {isSignup ? 'Already have an account? Log in' : "Don't have an account? Sign up"}
        </button>
        <p className="text-[10px] text-gray-600 text-center uppercase tracking-widest px-8">
          By continuing, you agree to our terms of service and security policy.
        </p>
      </div>
    </div>
  );
};

export default AuthScreen;

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { UserProfile } from '../types';
import { firebaseService } from '../firebase';

interface HomeScreenProps {
  user: UserProfile;
  onLogout: () => void;
  onTriggerSOS: () => void;
  onSettings: () => void;
  onTrustedView: () => void;
  refreshUser: () => void;
}

const HomeScreen: React.FC<HomeScreenProps> = ({ user, onLogout, onTriggerSOS, onSettings, onTrustedView, refreshUser }) => {
  const [isArmed, setIsArmed] = useState(user.isArmed);
  const [isListening, setIsListening] = useState(false);
  const recognitionRef = useRef<any>(null);

  // Initialize Speech Recognition
  useEffect(() => {
    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
    if (SpeechRecognition) {
      recognitionRef.current = new SpeechRecognition();
      recognitionRef.current.continuous = true;
      recognitionRef.current.interimResults = false;
      recognitionRef.current.lang = 'en-US';

      recognitionRef.current.onresult = (event: any) => {
        const transcript = event.results[event.results.length - 1][0].transcript.trim().toUpperCase();
        console.log("Recognized:", transcript);
        if (transcript.includes(user.emergencyKeyword.toUpperCase())) {
          onTriggerSOS();
        }
      };

      recognitionRef.current.onend = () => {
        if (isArmed) {
          recognitionRef.current.start();
        }
      };
    }
  }, [isArmed, user.emergencyKeyword, onTriggerSOS]);

  const toggleArm = () => {
    const newState = !isArmed;
    setIsArmed(newState);
    firebaseService.updateProfile(user.userId, { isArmed: newState });
    refreshUser();

    if (newState && recognitionRef.current) {
      try {
        recognitionRef.current.start();
        setIsListening(true);
      } catch (e) { console.error(e); }
    } else if (recognitionRef.current) {
      recognitionRef.current.stop();
      setIsListening(false);
    }
  };

  return (
    <div className="flex flex-col h-full w-full bg-[#0F1115]">
      {/* Header */}
      <div className="flex justify-between items-center p-6 bg-[#1A1D24]">
        <div className="flex items-center gap-3">
          <div className="w-10 h-10 rounded-full bg-gray-800 flex items-center justify-center">
            <i className="fa-solid fa-user text-gray-400"></i>
          </div>
          <div>
            <h3 className="text-sm font-bold text-white leading-none">{user.name}</h3>
            <span className="text-[10px] text-green-500 uppercase tracking-tighter">Identity Verified</span>
          </div>
        </div>
        <div className="flex gap-4">
          <button onClick={onSettings} className="p-2 text-gray-400 hover:text-white">
            <i className="fa-solid fa-cog text-xl"></i>
          </button>
          <button onClick={onLogout} className="p-2 text-gray-400 hover:text-white">
            <i className="fa-solid fa-arrow-right-from-bracket text-xl"></i>
          </button>
        </div>
      </div>

      <div className="flex-1 flex flex-col items-center justify-center px-6">
        {/* Armed Indicator */}
        <div className={`relative w-64 h-64 rounded-full border-2 ${isArmed ? 'border-red-500' : 'border-gray-800'} flex items-center justify-center transition-all duration-500`}>
          {isArmed && (
             <div className="absolute inset-0 rounded-full border-4 border-red-500/20 animate-ping"></div>
          )}
          <button 
            onClick={toggleArm}
            className={`w-48 h-48 rounded-full ${isArmed ? 'bg-[#D32F2F]' : 'bg-[#1A1D24]'} shadow-2xl flex flex-col items-center justify-center transition-all active:scale-95`}
          >
            <i className={`fa-solid ${isArmed ? 'fa-shield-halved' : 'fa-shield'} text-5xl mb-3 text-white`}></i>
            <span className="text-lg font-black tracking-widest text-white uppercase">{isArmed ? 'ARMED' : 'DISARMED'}</span>
          </button>
        </div>

        <div className="mt-12 text-center w-full max-w-xs">
          <div className="bg-[#1A1D24] rounded-2xl p-4 border border-gray-800">
            <p className="text-gray-500 text-xs uppercase tracking-widest mb-2 font-bold">Voice Keyword</p>
            <div className="flex items-center justify-center gap-2">
              <span className="text-2xl font-mono text-white tracking-[0.2em]">****</span>
              <button className="text-[#D32F2F] text-xs font-bold uppercase ml-2">Show</button>
            </div>
          </div>

          <p className="text-gray-500 text-xs mt-4 leading-relaxed">
            {isArmed 
              ? 'App is listening for your keyword. Stay safe.' 
              : 'App is in standby. Voice trigger is currently disabled.'}
          </p>
        </div>
      </div>

      {/* Manual Panic Button Footer */}
      <div className="p-6 pb-10 bg-[#1A1D24] rounded-t-[3rem] shadow-[0_-20px_50px_rgba(0,0,0,0.5)]">
        <button 
          onClick={onTriggerSOS}
          className="w-full bg-[#D32F2F] text-white py-5 rounded-2xl flex items-center justify-center gap-3 font-black text-xl tracking-widest transition-all active:scale-95 hover:bg-red-700"
        >
          <i className="fa-solid fa-burst animate-pulse"></i>
          PANIC SOS
        </button>

        <div className="mt-6 flex justify-between items-center px-4">
          <button onClick={onTrustedView} className="flex flex-col items-center gap-1 group">
            <div className="w-12 h-12 rounded-full bg-gray-800 flex items-center justify-center group-hover:bg-[#D32F2F] transition-colors">
              <i className="fa-solid fa-people-group text-white"></i>
            </div>
            <span className="text-[10px] text-gray-500 font-bold uppercase tracking-wider">Trusted View</span>
          </button>

          <div className="flex flex-col items-center gap-1">
            <div className="flex gap-1">
              <div className={`w-2 h-2 rounded-full ${isListening ? 'bg-red-500 animate-pulse' : 'bg-gray-700'}`}></div>
              <div className="w-2 h-2 rounded-full bg-green-500"></div>
              <div className="w-2 h-2 rounded-full bg-blue-500"></div>
            </div>
            <span className="text-[10px] text-gray-500 font-bold uppercase tracking-wider">System Ready</span>
          </div>
        </div>
      </div>
    </div>
  );
};

export default HomeScreen;

import React, { useState, useEffect, useRef } from 'react';
import { UserProfile, EmergencyRecord, EmergencyStatus, LocationUpdate } from '../types';
import { firebaseService } from '../firebase';

interface EmergencyScreenProps {
  user: UserProfile;
  emergency: EmergencyRecord;
  onResolve: () => void;
}

const EmergencyScreen: React.FC<EmergencyScreenProps> = ({ user, emergency, onResolve }) => {
  const [locations, setLocations] = useState<LocationUpdate[]>([]);
  const [currentCoords, setCurrentCoords] = useState<{lat: number, lng: number} | null>(null);
  const watchIdRef = useRef<number | null>(null);

  useEffect(() => {
    // Start tracking location
    if ("geolocation" in navigator) {
      watchIdRef.current = navigator.geolocation.watchPosition(
        (position) => {
          const { latitude, longitude } = position.coords;
          const newLoc: LocationUpdate = {
            emergencyId: emergency.emergencyId,
            latitude,
            longitude,
            timestamp: Date.now()
          };
          firebaseService.pushLocation(newLoc);
          setCurrentCoords({ lat: latitude, lng: longitude });
          setLocations(prev => [...prev, newLoc]);
        },
        (error) => console.error(error),
        { enableHighAccuracy: true, timeout: 5000, maximumAge: 0 }
      );
    }

    return () => {
      if (watchIdRef.current !== null) {
        navigator.geolocation.clearWatch(watchIdRef.current);
      }
    };
  }, [emergency.emergencyId]);

  return (
    <div className="flex flex-col h-full w-full bg-[#0F1115]">
      {/* Alert Banner */}
      <div className="bg-[#D32F2F] p-4 flex items-center justify-between animate-pulse">
        <div className="flex items-center gap-3">
          <i className="fa-solid fa-triangle-exclamation text-white text-xl"></i>
          <div>
            <h2 className="text-white font-black uppercase text-sm tracking-widest">SOS ACTIVATED</h2>
            <p className="text-white/80 text-[10px] uppercase font-bold">Broadcasting Live Location</p>
          </div>
        </div>
        <div className="text-white text-xs font-mono">
          ID: {emergency.emergencyId.substr(-6)}
        </div>
      </div>

      {/* Map View */}
      <div className="flex-1 relative bg-gray-900 overflow-hidden">
        {/* Simulated Map Container */}
        <div className="absolute inset-0 flex items-center justify-center opacity-30 pointer-events-none">
           <i className="fa-solid fa-map-location-dot text-9xl"></i>
        </div>

        {currentCoords ? (
          <div className="absolute inset-0 p-4">
             <div className="bg-[#1A1D24]/80 backdrop-blur-md rounded-2xl p-4 border border-white/10 mb-4">
               <div className="flex justify-between items-center mb-2">
                 <span className="text-[10px] text-gray-400 font-bold uppercase">Current Coordinates</span>
                 <span className="text-[10px] text-green-500 font-bold animate-pulse">● LIVE</span>
               </div>
               <div className="text-lg font-mono text-white">
                 {currentCoords.lat.toFixed(4)}°, {currentCoords.lng.toFixed(4)}°
               </div>
             </div>

             {/* Movement Log */}
             <div className="h-64 overflow-y-auto space-y-2 pr-2 scrollbar-hide">
               {locations.slice().reverse().map((loc, idx) => (
                 <div key={idx} className="bg-gray-800/50 p-2 rounded-lg border border-gray-700 text-[10px] flex justify-between">
                   <span className="text-gray-400">{new Date(loc.timestamp).toLocaleTimeString()}</span>
                   <span className="text-white font-mono">{loc.latitude.toFixed(5)}, {loc.longitude.toFixed(5)}</span>
                 </div>
               ))}
             </div>
          </div>
        ) : (
          <div className="h-full w-full flex flex-col items-center justify-center p-8 text-center">
            <div className="w-16 h-16 border-4 border-[#D32F2F] border-t-transparent rounded-full animate-spin mb-4"></div>
            <p className="text-gray-400 font-bold uppercase text-xs tracking-widest">Acquiring GPS Signal...</p>
          </div>
        )}

        {/* Pulsing Marker Overlay */}
        {currentCoords && (
          <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 flex flex-col items-center">
             <div className="w-12 h-12 bg-[#D32F2F] rounded-full flex items-center justify-center animate-pulse-red shadow-2xl z-10">
                <i className="fa-solid fa-person-running text-white text-2xl"></i>
             </div>
             <div className="mt-2 bg-black/80 px-2 py-1 rounded text-[10px] text-white font-bold uppercase">You are here</div>
          </div>
        )}
      </div>

      {/* Control Footer */}
      <div className="p-6 bg-[#1A1D24] rounded-t-3xl space-y-4">
        <div className="flex items-center gap-4">
           <div className="flex-1 bg-gray-800 p-4 rounded-xl">
             <p className="text-gray-500 text-[10px] uppercase font-bold mb-1">Status</p>
             <p className="text-white text-sm font-bold uppercase tracking-widest">Active Emergency</p>
           </div>
           <div className="flex-1 bg-gray-800 p-4 rounded-xl">
             <p className="text-gray-500 text-[10px] uppercase font-bold mb-1">Contacts Notified</p>
             <p className="text-white text-sm font-bold">3 Individuals</p>
           </div>
        </div>

        <button 
          onClick={onResolve}
          className="w-full bg-[#1A1D24] border-2 border-green-500 text-green-500 py-4 rounded-xl font-black text-lg tracking-widest transition-all active:scale-95 flex items-center justify-center gap-2"
        >
          <i className="fa-solid fa-check-circle"></i>
          I AM SAFE
        </button>
      </div>
    </div>
  );
};

export default EmergencyScreen;

import React, { useState, useEffect } from 'react';
import { UserProfile, Contact } from '../types';
import { firebaseService } from '../firebase';

interface SettingsScreenProps {
  user: UserProfile;
  onBack: () => void;
  refreshUser: () => void;
}

const SettingsScreen: React.FC<SettingsScreenProps> = ({ user, onBack, refreshUser }) => {
  const [keyword, setKeyword] = useState(user.emergencyKeyword);
  const [contacts, setContacts] = useState<Contact[]>([]);
  const [newContact, setNewContact] = useState({ name: '', phone: '' });

  useEffect(() => {
    setContacts(firebaseService.getContacts(user.userId));
  }, [user.userId]);

  const saveKeyword = () => {
    firebaseService.updateProfile(user.userId, { emergencyKeyword: keyword.toUpperCase() });
    refreshUser();
    alert("Keyword updated successfully.");
  };

  const addContact = () => {
    if (!newContact.name || !newContact.phone) return;
    const contact: Contact = {
      contactId: 'c_' + Date.now(),
      userId: user.userId,
      name: newContact.name,
      phone: newContact.phone,
      relationship: 'Trusted'
    };
    firebaseService.addContact(contact);
    setContacts([...contacts, contact]);
    setNewContact({ name: '', phone: '' });
  };

  const deleteContact = (id: string) => {
    firebaseService.deleteContact(id);
    setContacts(contacts.filter(c => c.contactId !== id));
  };

  return (
    <div className="flex flex-col h-full w-full bg-[#0F1115]">
      <div className="p-6 flex items-center gap-4 bg-[#1A1D24]">
        <button onClick={onBack} className="text-gray-400 hover:text-white">
          <i className="fa-solid fa-arrow-left text-xl"></i>
        </button>
        <h2 className="text-xl font-bold text-white uppercase tracking-widest">Emergency Config</h2>
      </div>

      <div className="flex-1 overflow-y-auto p-6 space-y-8">
        {/* Keyword Setting */}
        <section>
          <h3 className="text-xs text-gray-500 uppercase font-bold tracking-widest mb-4">Voice Trigger</h3>
          <div className="bg-[#1A1D24] p-4 rounded-2xl border border-gray-800">
            <p className="text-xs text-gray-400 mb-3">Set a unique word that will trigger the SOS even when the phone is locked.</p>
            <div className="flex gap-2">
              <input 
                value={keyword}
                onChange={(e) => setKeyword(e.target.value.toUpperCase())}
                className="flex-1 bg-black/30 border border-gray-700 rounded-lg p-3 text-white font-mono tracking-widest focus:outline-none"
                placeholder="E.G. HELP"
              />
              <button 
                onClick={saveKeyword}
                className="bg-[#D32F2F] text-white px-4 rounded-lg font-bold text-xs uppercase"
              >
                Save
              </button>
            </div>
          </div>
        </section>

        {/* Contacts Section */}
        <section>
          <h3 className="text-xs text-gray-500 uppercase font-bold tracking-widest mb-4">Trusted Contacts ({contacts.length}/5)</h3>

          <div className="space-y-3 mb-6">
            {contacts.map(contact => (
              <div key={contact.contactId} className="bg-[#1A1D24] p-4 rounded-2xl border border-gray-800 flex justify-between items-center">
                <div className="flex items-center gap-3">
                  <div className="w-10 h-10 rounded-full bg-gray-800 flex items-center justify-center">
                    <i className="fa-solid fa-heart text-[#D32F2F]"></i>
                  </div>
                  <div>
                    <h4 className="text-sm font-bold text-white">{contact.name}</h4>
                    <p className="text-xs text-gray-500">{contact.phone}</p>
                  </div>
                </div>
                <button onClick={() => deleteContact(contact.contactId)} className="text-gray-600 hover:text-red-500">
                  <i className="fa-solid fa-trash-can"></i>
                </button>
              </div>
            ))}
          </div>

          <div className="bg-[#1A1D24] p-4 rounded-2xl border border-dashed border-gray-700">
             <p className="text-[10px] text-gray-500 uppercase font-bold mb-3">Add New Contact</p>
             <div className="space-y-2">
                <input 
                  placeholder="Full Name"
                  value={newContact.name}
                  onChange={(e) => setNewContact({...newContact, name: e.target.value})}
                  className="w-full bg-black/30 border border-gray-700 rounded-lg p-3 text-white text-sm"
                />
                <input 
                  placeholder="Phone Number"
                  value={newContact.phone}
                  onChange={(e) => setNewContact({...newContact, phone: e.target.value})}
                  className="w-full bg-black/30 border border-gray-700 rounded-lg p-3 text-white text-sm"
                />
                <button 
                  onClick={addContact}
                  className="w-full bg-gray-800 text-white font-bold py-3 rounded-lg text-xs uppercase"
                >
                  Confirm Addition
                </button>
             </div>
          </div>
        </section>

        <section className="bg-amber-500/10 border border-amber-500/20 p-4 rounded-xl">
           <div className="flex gap-3">
              <i className="fa-solid fa-circle-info text-amber-500 mt-1"></i>
              <div>
                 <h4 className="text-sm font-bold text-amber-500 mb-1">Safety Tip</h4>
                 <p className="text-xs text-gray-400">Choose a keyword that is unique but easy to remember. Avoid common words used in daily conversation.</p>
              </div>
           </div>
        </section>
      </div>
    </div>
  );
};

export default SettingsScreen;

import React, { useState, useEffect } from 'react';
import { EmergencyRecord, LocationUpdate, EmergencyStatus } from '../types';
import { firebaseService } from '../firebase';

interface TrustedContactViewProps {
  onBack: () => void;
}

const TrustedContactView: React.FC<TrustedContactViewProps> = ({ onBack }) => {
  const [emergencies, setEmergencies] = useState<EmergencyRecord[]>([]);
  const [selectedEmergency, setSelectedEmergency] = useState<string | null>(null);
  const [locations, setLocations] = useState<LocationUpdate[]>([]);

  useEffect(() => {
    const db = JSON.parse(localStorage.getItem('SAFE_VOICE_DB') || '{}');
    setEmergencies(db.emergencies || []);
  }, []);

  useEffect(() => {
    if (selectedEmergency) {
      const interval = setInterval(() => {
        setLocations(firebaseService.getEmergencyLocations(selectedEmergency));
      }, 2000);
      return () => clearInterval(interval);
    }
  }, [selectedEmergency]);

  const handleResolve = () => {
    if (selectedEmergency) {
      firebaseService.resolveEmergency(selectedEmergency);
      alert("Emergency marked as SAFE by Authority.");
      onBack();
    }
  };

  const activeEmergencies = emergencies.filter(e => e.status === EmergencyStatus.ACTIVE);

  return (
    <div className="flex flex-col h-full w-full bg-[#0F1115]">
      <div className="p-6 flex items-center justify-between bg-[#1A1D24]">
        <div className="flex items-center gap-3">
          <button onClick={onBack} className="text-gray-400">
            <i className="fa-solid fa-arrow-left text-xl"></i>
          </button>
          <h2 className="text-xl font-bold text-white uppercase tracking-widest">Responder Hub</h2>
        </div>
        <div className="w-8 h-8 rounded-full bg-blue-500 flex items-center justify-center animate-pulse">
          <i className="fa-solid fa-radio text-white text-xs"></i>
        </div>
      </div>

      <div className="flex-1 p-6 space-y-6 overflow-y-auto">
        {activeEmergencies.length === 0 ? (
          <div className="flex flex-col items-center justify-center h-64 text-center">
            <i className="fa-solid fa-shield-check text-gray-800 text-6xl mb-4"></i>
            <h3 className="text-gray-500 font-bold uppercase tracking-widest">All Systems Secure</h3>
            <p className="text-gray-600 text-xs mt-2">No active emergencies detected in your circle.</p>
          </div>
        ) : (
          <div className="space-y-4">
            <h3 className="text-xs text-red-500 font-black uppercase tracking-[0.2em] animate-pulse">Critical Alerts</h3>
            {activeEmergencies.map(e => (
              <div 
                key={e.emergencyId} 
                onClick={() => setSelectedEmergency(e.emergencyId)}
                className={`p-4 rounded-2xl border ${selectedEmergency === e.emergencyId ? 'bg-red-900/30 border-red-500' : 'bg-[#1A1D24] border-gray-800'} transition-all`}
              >
                <div className="flex justify-between items-start mb-2">
                  <span className="text-xs text-white font-bold">User Emergency: {e.userId.substr(0,8)}</span>
                  <span className="text-[10px] text-gray-500 font-mono">{new Date(e.triggeredAt).toLocaleTimeString()}</span>
                </div>
                <div className="flex items-center gap-2 text-red-400 text-[10px] font-bold uppercase">
                  <span className="w-1.5 h-1.5 rounded-full bg-red-500 animate-ping"></span>
                  Active Location Broadcast
                </div>
              </div>
            ))}
          </div>
        )}

        {selectedEmergency && (
          <div className="bg-[#1A1D24] rounded-2xl p-6 border border-gray-800 space-y-4 shadow-2xl">
            <h4 className="text-sm font-bold text-white flex items-center gap-2">
              <i className="fa-solid fa-location-crosshairs text-[#D32F2F]"></i>
              Live Tracking Data
            </h4>

            <div className="h-48 bg-black/40 rounded-xl overflow-y-auto p-4 space-y-2 border border-white/5">
              {locations.length > 0 ? (
                locations.slice().reverse().map((l, i) => (
                  <div key={i} className="text-[10px] font-mono text-gray-400 border-b border-gray-800 pb-1 flex justify-between">
                    <span>{new Date(l.timestamp).toLocaleTimeString()}</span>
                    <span className="text-white">{l.latitude.toFixed(5)}, {l.longitude.toFixed(5)}</span>
                  </div>
                ))
              ) : (
                <div className="h-full flex items-center justify-center">
                  <p className="text-[10px] text-gray-600 uppercase font-bold italic">Waiting for broadcast packets...</p>
                </div>
              )}
            </div>

            <button 
              onClick={handleResolve}
              className="w-full bg-green-600 text-white font-black py-4 rounded-xl uppercase tracking-widest transition-all active:scale-95"
            >
              Mark User as SAFE
            </button>
          </div>
        )}
      </div>

      <div className="p-6 bg-[#0F1115] border-t border-gray-900">
        <p className="text-[10px] text-gray-700 text-center font-bold uppercase tracking-[0.2em]">
          End-to-End Encryption Enabled
        </p>
      </div>
    </div>
  );
};

