import { UserProfile, Contact, EmergencyRecord, LocationUpdate, EmergencyStatus } from './types';

const STORAGE_KEY = 'SAFE_VOICE_DB';

const getDB = () => JSON.parse(localStorage.getItem(STORAGE_KEY) || '{"users":{}, "contacts":[], "emergencies":[], "locations":[]}');
const saveDB = (db: any) => localStorage.setItem(STORAGE_KEY, JSON.stringify(db));

export const firebaseService = {
  // AUTH
  getCurrentUser: (): UserProfile | null => {
    const userJson = localStorage.getItem('SAFE_VOICE_SESSION');
    return userJson ? JSON.parse(userJson) : null;
  },

  signUp: async (name: string, email: string, phone: string): Promise<UserProfile> => {
    const db = getDB();
    if (db.users[email]) {
      throw new Error("User already exists");
    }
    const user: UserProfile = {
      userId: 'u_' + Math.random().toString(36).substr(2, 9),
      name,
      email,
      phone,
      emergencyKeyword: 'HELP',
      isArmed: false,
      createdAt: Date.now()
    };
    db.users[email] = user;
    saveDB(db);
    localStorage.setItem('SAFE_VOICE_SESSION', JSON.stringify(user));
    return user;
  },

  login: async (email: string): Promise<UserProfile> => {
    const db = getDB();
    const user = db.users[email] as UserProfile;
    if (!user) {
      throw new Error("User not found. Please sign up.");
    }
    localStorage.setItem('SAFE_VOICE_SESSION', JSON.stringify(user));
    return user;
  },

  logout: () => {
    localStorage.removeItem('SAFE_VOICE_SESSION');
  },

  updateProfile: (userId: string, updates: Partial<UserProfile>) => {
    const db = getDB();
    // In our mock, email is the key
    const email = Object.keys(db.users).find(key => db.users[key].userId === userId);
    if (email && db.users[email]) {
      db.users[email] = { ...db.users[email], ...updates };
      saveDB(db);
      localStorage.setItem('SAFE_VOICE_SESSION', JSON.stringify(db.users[email]));
    }
  },

  // CONTACTS
  getContacts: (userId: string): Contact[] => {
    return getDB().contacts.filter((c: Contact) => c.userId === userId);
  },

  addContact: (contact: Contact) => {
    const db = getDB();
    db.contacts.push(contact);
    saveDB(db);
  },

  deleteContact: (contactId: string) => {
    const db = getDB();
    db.contacts = db.contacts.filter((c: Contact) => c.contactId !== contactId);
    saveDB(db);
  },

  // EMERGENCY
  triggerEmergency: (userId: string): string => {
    const db = getDB();
    const emergencyId = 'e_' + Date.now();
    const record: EmergencyRecord = {
      emergencyId,
      userId,
      status: EmergencyStatus.ACTIVE,
      triggeredAt: Date.now()
    };
    db.emergencies.push(record);
    saveDB(db);

    // Simulate SMS Sending
    const contacts = this.firebaseService.getContacts(userId);
    console.log(`[SMS GATEWAY] Sending SOS alerts to ${contacts.length} contacts...`);
    contacts.forEach(c => {
        console.log(`[SMS] To: ${c.phone} | Msg: EMERGENCY! ${userId} has triggered an SOS. Live tracking: safe-voice.app/track/${emergencyId}`);
    });

    return emergencyId;
  },

  resolveEmergency: (emergencyId: string) => {
    const db = getDB();
    const record = db.emergencies.find((e: EmergencyRecord) => e.emergencyId === emergencyId);
    if (record) {
      record.status = EmergencyStatus.SAFE;
      record.resolvedAt = Date.now();
      saveDB(db);
    }
  },

  getActiveEmergency: (userId: string): EmergencyRecord | undefined => {
    return getDB().emergencies.find((e: EmergencyRecord) => e.userId === userId && e.status === EmergencyStatus.ACTIVE);
  },

  // LOCATIONS
  pushLocation: (location: LocationUpdate) => {
    const db = getDB();
    db.locations.push(location);
    saveDB(db);
  },

  getEmergencyLocations: (emergencyId: string): LocationUpdate[] => {
    return getDB().locations.filter((l: LocationUpdate) => l.emergencyId === emergencyId);
  }
};

import React, { useState } from 'react';
import { firebaseService } from '../firebase';
import { UserProfile } from '../types';

interface AuthScreenProps {
  onLogin: (user: UserProfile) => void;
}

const AuthScreen: React.FC<AuthScreenProps> = ({ onLogin }) => {
  const [isSignup, setIsSignup] = useState(false);
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [name, setName] = useState('');
  const [phone, setPhone] = useState('');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setLoading(true);

    try {
      if (isSignup) {
        if (!name || !phone || !email || !password) throw new Error("Please fill all fields");
        const user = await firebaseService.signUp(name, email, phone);
        onLogin(user);
      } else {
        if (!email || !password) throw new Error("Please fill all fields");
        const user = await firebaseService.login(email);
        onLogin(user);
      }
    } catch (err: any) {
      setError(err.message || "Authentication failed");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="flex flex-col h-full w-full p-8 bg-[#0F1115] overflow-y-auto">
      <div className="mt-8 mb-10 text-center">
        <div className="inline-flex items-center justify-center w-16 h-16 bg-[#D32F2F] rounded-2xl mb-4 shadow-lg shadow-red-900/20">
          <i className="fa-solid fa-shield-heart text-3xl text-white"></i>
        </div>
        <h2 className="text-3xl font-black text-white uppercase tracking-tighter">
          {isSignup ? 'Create Guard' : 'Secure Entry'}
        </h2>
        <p className="text-gray-500 text-sm font-medium mt-1">SAFE-VOICE Identity Service</p>
      </div>

      <form onSubmit={handleSubmit} className="flex flex-col gap-4">
        {error && (
          <div className="bg-red-500/10 border border-red-500/50 p-3 rounded-xl text-red-500 text-xs font-bold text-center animate-bounce">
            {error}
          </div>
        )}

        {isSignup && (
          <>
            <div className="flex flex-col gap-1">
              <label className="text-[10px] text-gray-500 uppercase font-black tracking-widest ml-1">Full Name</label>
              <input 
                type="text"
                value={name}
                onChange={(e) => setName(e.target.value)}
                className="w-full bg-[#1A1D24] border border-gray-800 rounded-xl p-4 text-white focus:outline-none focus:border-[#D32F2F] transition-colors"
                placeholder="John Doe"
              />
            </div>
            <div className="flex flex-col gap-1">
              <label className="text-[10px] text-gray-500 uppercase font-black tracking-widest ml-1">Mobile Number</label>
              <input 
                type="tel"
                value={phone}
                onChange={(e) => setPhone(e.target.value)}
                className="w-full bg-[#1A1D24] border border-gray-800 rounded-xl p-4 text-white focus:outline-none focus:border-[#D32F2F] transition-colors"
                placeholder="+1 234 567 890"
              />
            </div>
          </>
        )}

        <div className="flex flex-col gap-1">
          <label className="text-[10px] text-gray-500 uppercase font-black tracking-widest ml-1">Email Protocol</label>
          <input 
            type="email"
            value={email}
            onChange={(e) => setEmail(e.target.value)}
            className="w-full bg-[#1A1D24] border border-gray-800 rounded-xl p-4 text-white focus:outline-none focus:border-[#D32F2F] transition-colors"
            placeholder="auth@safevoice.net"
            required
          />
        </div>

        <div className="flex flex-col gap-1">
          <label className="text-[10px] text-gray-500 uppercase font-black tracking-widest ml-1">Cipher Key</label>
          <input 
            type="password"
            value={password}
            onChange={(e) => setPassword(e.target.value)}
            className="w-full bg-[#1A1D24] border border-gray-800 rounded-xl p-4 text-white focus:outline-none focus:border-[#D32F2F] transition-colors"
            placeholder="••••••••"
            required
          />
        </div>

        <button 
          type="submit"
          disabled={loading}
          className={`w-full ${loading ? 'opacity-50 cursor-not-allowed' : 'bg-[#D32F2F] hover:bg-red-700'} text-white font-black py-4 rounded-xl mt-4 shadow-xl shadow-red-900/20 transition-all active:scale-95 uppercase tracking-widest`}
        >
          {loading ? (
            <div className="flex items-center justify-center gap-2">
              <i className="fa-solid fa-circle-notch animate-spin"></i>
              <span>Verifying...</span>
            </div>
          ) : (isSignup ? 'Initialize Account' : 'Authenticate')}
        </button>
      </form>

      <div className="mt-8 mb-8 text-center">
        <button 
          onClick={() => {
            setIsSignup(!isSignup);
            setError('');
          }}
          className="text-gray-400 text-sm font-bold hover:text-white transition-colors underline decoration-red-500/50 underline-offset-4"
        >
          {isSignup ? 'Already registered? System Login' : "New operative? Register here"}
        </button>
      </div>

      <p className="mt-auto text-[10px] text-gray-700 text-center font-bold uppercase tracking-[0.2em] leading-relaxed">
        MIL-SPEC ENCRYPTION ENABLED<br/>
        REAL-TIME GEOLOCATION BYPASS SECURE
      </p>
    </div>
  );
};

