import React, { useState, useEffect, useRef } from 'react';
import { UserProfile, EmergencyRecord, LocationUpdate } from '../types';
import { firebaseService } from '../firebase';

// Extend window for Leaflet
declare const L: any;

interface EmergencyScreenProps {
  user: UserProfile;
  emergency: EmergencyRecord;
  onResolve: () => void;
}

const EmergencyScreen: React.FC<EmergencyScreenProps> = ({ user, emergency, onResolve }) => {
  const [locations, setLocations] = useState<LocationUpdate[]>([]);
  const [currentCoords, setCurrentCoords] = useState<{lat: number, lng: number} | null>(null);
  const mapRef = useRef<any>(null);
  const markerRef = useRef<any>(null);
  const watchIdRef = useRef<number | null>(null);
  const [smsLog, setSmsLog] = useState<string[]>([]);

  useEffect(() => {
    // Initial map setup
    const container = document.getElementById('map');
    if (container && !mapRef.current) {
      mapRef.current = L.map('map', {
        zoomControl: false,
        attributionControl: false
      }).setView([0, 0], 2);

      L.tileLayer('https://{s}.basemaps.cartocdn.com/dark_all/{z}/{x}/{y}{r}.png', {
        maxZoom: 19
      }).addTo(mapRef.current);
    }

    // Start tracking location
    if ("geolocation" in navigator) {
      watchIdRef.current = navigator.geolocation.watchPosition(
        (position) => {
          const { latitude, longitude } = position.coords;
          const newLoc: LocationUpdate = {
            emergencyId: emergency.emergencyId,
            latitude,
            longitude,
            timestamp: Date.now()
          };

          firebaseService.pushLocation(newLoc);
          setCurrentCoords({ lat: latitude, lng: longitude });
          setLocations(prev => [...prev, newLoc]);

          // Update Map
          if (mapRef.current) {
            mapRef.current.setView([latitude, longitude], 16);
            if (markerRef.current) {
              markerRef.current.setLatLng([latitude, longitude]);
            } else {
              const pulseIcon = L.divIcon({
                className: 'custom-div-icon',
                html: `<div style="background-color: #D32F2F; width: 24px; height: 24px; border-radius: 50%; border: 4px solid white; box-shadow: 0 0 15px #D32F2F;" class="animate-pulse"></div>`,
                iconSize: [24, 24],
                iconAnchor: [12, 12]
              });
              markerRef.current = L.marker([latitude, longitude], { icon: pulseIcon }).addTo(mapRef.current);
            }
          }
        },
        (error) => console.error("GPS Error:", error),
        { enableHighAccuracy: true, timeout: 5000, maximumAge: 0 }
      );
    }

    // Simulate SMS notification success
    const contacts = firebaseService.getContacts(user.userId);
    const msgs = contacts.map(c => `SMS delivered to ${c.name} (${c.phone})`);
    setSmsLog(msgs);

    return () => {
      if (watchIdRef.current !== null) {
        navigator.geolocation.clearWatch(watchIdRef.current);
      }
      if (mapRef.current) {
        mapRef.current.remove();
        mapRef.current = null;
      }
    };
  }, [emergency.emergencyId, user.userId]);

  return (
    <div className="flex flex-col h-full w-full bg-[#0F1115]">
      {/* Critical Status Bar */}
      <div className="bg-[#D32F2F] p-5 flex items-center justify-between shadow-2xl z-20">
        <div className="flex items-center gap-4">
          <div className="w-10 h-10 bg-white rounded-full flex items-center justify-center animate-bounce">
            <i className="fa-solid fa-triangle-exclamation text-[#D32F2F] text-xl"></i>
          </div>
          <div>
            <h2 className="text-white font-black uppercase text-base tracking-widest leading-none">SOS ACTIVE</h2>
            <p className="text-white/80 text-[10px] uppercase font-bold tracking-tighter mt-1">Real-time GPS Uplink Established</p>
          </div>
        </div>
        <div className="flex flex-col items-end">
           <div className="bg-black/20 px-2 py-1 rounded text-[10px] font-mono text-white mb-1">TX: 5.2kbps</div>
           <div className="text-white text-[10px] font-mono">#{emergency.emergencyId.substr(-6)}</div>
        </div>
      </div>

      {/* Map Content */}
      <div className="flex-1 relative">
        <div id="map" className="absolute inset-0 z-0"></div>

        {/* SMS Notification Overlay */}
        <div className="absolute top-4 left-4 right-4 z-10 space-y-2 pointer-events-none">
          {smsLog.map((log, i) => (
