            </div>
            <div className="absolute -top-1 -right-1 w-3 h-3 bg-green-500 border-2 border-[#1A1D24] rounded-full"></div>
          </div>
          <div>
            <h3 className="text-sm font-black text-white leading-none tracking-tight">{user.name}</h3>
            <span className="text-[9px] text-gray-500 uppercase font-black tracking-widest mt-1 block">Active Operative</span>
          </div>
        </div>
        <div className="flex gap-2">
          <button onClick={onSettings} className="w-10 h-10 rounded-xl bg-gray-800/50 flex items-center justify-center text-gray-400 hover:text-white transition-all active:scale-90 border border-gray-700">
            <i className="fa-solid fa-sliders text-sm"></i>
          </button>
          <button onClick={onLogout} className="w-10 h-10 rounded-xl bg-gray-800/50 flex items-center justify-center text-gray-400 hover:text-red-500 transition-all active:scale-90 border border-gray-700">
            <i className="fa-solid fa-power-off text-sm"></i>
          </button>
        </div>
      </div>

      {/* Main Control Center */}
      <div className="flex-1 flex flex-col items-center justify-center px-8">
        <div className={`relative w-72 h-72 rounded-[3rem] border-2 ${isArmed ? 'border-red-500 shadow-[0_0_50px_rgba(211,47,47,0.2)]' : 'border-gray-800'} flex items-center justify-center transition-all duration-700`}>
          {isArmed && (
             <div className="absolute inset-0 rounded-[3rem] border-8 border-red-500/10 animate-ping"></div>
          )}
          <button 
            onClick={toggleArm}
            className={`w-56 h-56 rounded-[2.5rem] ${isArmed ? 'bg-[#D32F2F]' : 'bg-[#1A1D24]'} shadow-2xl flex flex-col items-center justify-center transition-all active:scale-95 relative overflow-hidden group`}
          >
