declare const L: any;

interface EmergencyScreenProps {
  user: UserProfile;
  emergency: EmergencyRecord;
  onResolve: () => void;
}

const EmergencyScreen: React.FC<EmergencyScreenProps> = ({ user, emergency, onResolve }) => {
  const [locations, setLocations] = useState<LocationUpdate[]>([]);
  const [currentCoords, setCurrentCoords] = useState<{lat: number, lng: number} | null>(null);
  const mapRef = useRef<any>(null);
  const markerRef = useRef<any>(null);
  const watchIdRef = useRef<number | null>(null);
  const [smsDeliveryStatus, setSmsDeliveryStatus] = useState<string[]>([]);

  useEffect(() => {
    // SMS Simulation on mount
    const contacts = firebaseService.getContacts(user.userId);
    setSmsDeliveryStatus(contacts.map(c => `ALERT: Sent to ${c.name}`));

    // Map initialization
    const timer = setTimeout(() => {
      const container = document.getElementById('map');
      if (container && !mapRef.current) {
        mapRef.current = L.map('map', { zoomControl: false, attributionControl: false }).setView([0, 0], 2);
        L.tileLayer('https://{s}.basemaps.cartocdn.com/dark_all/{z}/{x}/{y}{r}.png', { maxZoom: 19 }).addTo(mapRef.current);
      }
    }, 100);

    // Geolocation monitoring
    if ("geolocation" in navigator) {
      watchIdRef.current = navigator.geolocation.watchPosition(
        (position) => {
          const { latitude, longitude } = position.coords;
          const newLoc = { emergencyId: emergency.emergencyId, latitude, longitude, timestamp: Date.now() };

          firebaseService.pushLocation(newLoc);
          setCurrentCoords({ lat: latitude, lng: longitude });
          setLocations(prev => [...prev, newLoc].slice(-20)); // Keep last 20 for UI

          if (mapRef.current) {
            mapRef.current.setView([latitude, longitude], 17);
            if (markerRef.current) {
              markerRef.current.setLatLng([latitude, longitude]);
            } else {
              const pulseIcon = L.divIcon({
                className: 'custom-icon',
                html: `<div style="background-color: #D32F2F; width: 28px; height: 28px; border-radius: 50%; border: 4px solid white; box-shadow: 0 0 20px #D32F2F;" class="animate-pulse"></div>`,
                iconSize: [28, 28],
                iconAnchor: [14, 14]
              });
              markerRef.current = L.marker([latitude, longitude], { icon: pulseIcon }).addTo(mapRef.current);
            }
          }
        },
        (error) => console.error("GPS UPLINK ERROR:", error),
        { enableHighAccuracy: true, timeout: 5000, maximumAge: 0 }
      );
    }

    return () => {
      clearTimeout(timer);
      if (watchIdRef.current !== null) navigator.geolocation.clearWatch(watchIdRef.current);
      if (mapRef.current) {
        mapRef.current.remove();
        mapRef.current = null;
      }
    };
  }, [emergency.emergencyId, user.userId]);

  return (
    <div className="flex flex-col h-full w-full bg-[#0F1115]">
      {/* Critical Alert Banner */}
      <div className="bg-[#D32F2F] p-5 flex items-center justify-between shadow-2xl z-20">
        <div className="flex items-center gap-4">
          <div className="w-12 h-12 bg-white rounded-2xl flex items-center justify-center animate-bounce shadow-xl">
            <i className="fa-solid fa-satellite-dish text-[#D32F2F] text-2xl"></i>
          </div>
          <div>
            <h2 className="text-white font-black uppercase text-lg tracking-widest leading-none">LIVE SOS</h2>
            <p className="text-white/70 text-[10px] uppercase font-black tracking-tighter mt-1">Real-time Location Stream Active</p>
          </div>
        </div>
        <div className="text-right">
           <div className="text-white font-mono text-[10px] bg-black/30 px-2 py-1 rounded">ID: {emergency.emergencyId.substr(-8)}</div>
        </div>
      </div>

      {/* Real Map View */}
      <div className="flex-1 relative">
        <div id="map" className="absolute inset-0 z-0"></div>

        {/* SMS Status Overlays */}
        <div className="absolute top-4 left-4 right-4 z-10 space-y-2 pointer-events-none">
          {smsDeliveryStatus.map((status, i) => (
            <div key={i} className="bg-green-600/90 backdrop-blur-md text-white text-[10px] font-black px-4 py-2 rounded-xl flex items-center gap-3 shadow-2xl animate-slide-in">
              <i className="fa-solid fa-paper-plane text-xs"></i>
              {status}
            </div>
          ))}
        </div>

        {/* Telemetry Card */}
        {currentCoords && (
          <div className="absolute bottom-6 left-4 right-4 z-10 bg-[#1A1D24]/90 backdrop-blur-2xl border border-white/10 rounded-[2rem] p-5 shadow-[0_20px_60px_rgba(0,0,0,0.8)]">
            <div className="flex justify-between items-center mb-4">
              <div className="flex items-center gap-2">
                <div className="w-2 h-2 rounded-full bg-green-500 animate-pulse"></div>
                <span className="text-[10px] text-gray-400 font-black uppercase tracking-widest">Global Positioning System</span>
              </div>
              <span className="text-[10px] text-white font-black bg-[#D32F2F] px-3 py-1 rounded-full shadow-inner">ACTIVE FIX</span>
            </div>

            <div className="flex gap-8 justify-around">
               <div className="text-center">
                 <p className="text-[9px] text-gray-500 font-black uppercase mb-1">Latitude</p>
                 <p className="text-white font-mono text-base font-bold tracking-tight">{currentCoords.lat.toFixed(6)}</p>
               </div>
               <div className="w-px bg-gray-800 h-10"></div>
               <div className="text-center">
                 <p className="text-[9px] text-gray-500 font-black uppercase mb-1">Longitude</p>
                 <p className="text-white font-mono text-base font-bold tracking-tight">{currentCoords.lng.toFixed(6)}</p>
