import React, { useState, useEffect, useRef } from 'react';
import { UserProfile, Contact } from '../types';
import { firebaseService } from '../firebase';

interface SettingsScreenProps {
  user: UserProfile;
  onBack: () => void;
  refreshUser: () => void;
}

const SettingsScreen: React.FC<SettingsScreenProps> = ({ user, onBack, refreshUser }) => {
  const [keyword, setKeyword] = useState(user.emergencyKeyword);
  const [contacts, setContacts] = useState<Contact[]>([]);
  const [newContact, setNewContact] = useState({ name: '', phone: '' });
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    setContacts(firebaseService.getContacts(user.userId));
  }, [user.userId]);

  const saveKeyword = () => {
    firebaseService.updateProfile(user.userId, { emergencyKeyword: keyword.toUpperCase() });
    refreshUser();
    alert("Voice Protocol Cipher Updated.");
  };

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        const base64String = reader.result as string;
        firebaseService.updateProfile(user.userId, { profilePic: base64String });
        refreshUser();
      };
      reader.readAsDataURL(file);
    }
  };

  const addContact = () => {
    if (!newContact.name || !newContact.phone) return;
    const contact: Contact = {
      contactId: 'c_' + Date.now(),
      userId: user.userId,
      name: newContact.name,
      phone: newContact.phone,
      relationship: 'Trusted'
    };
    firebaseService.addContact(contact);
    setContacts([...contacts, contact]);
    setNewContact({ name: '', phone: '' });
  };

  const deleteContact = (id: string) => {
    firebaseService.deleteContact(id);
    setContacts(contacts.filter(c => c.contactId !== id));
  };

  const userInitials = user.name.split(' ').map(n => n[0]).join('').toUpperCase().slice(0, 2);

  return (
    <div className="flex flex-col h-full w-full bg-[#0F1115]">
      <div className="p-6 pt-10 flex items-center gap-4 bg-[#1A1D24] border-b border-gray-800">
        <button onClick={onBack} className="w-10 h-10 rounded-xl bg-gray-800 flex items-center justify-center text-gray-400 hover:text-white transition-all">
          <i className="fa-solid fa-arrow-left"></i>
        </button>
        <h2 className="text-sm font-black text-white uppercase tracking-[0.25em]">Config Terminal</h2>
      </div>

      <div className="flex-1 overflow-y-auto p-6 space-y-8 pb-10">
        {/* Profile Identity Section */}
        <section>
          <div className="flex justify-between items-center mb-4">
             <h3 className="text-[10px] text-gray-500 uppercase font-black tracking-widest">Biometric Identity</h3>
             <i className="fa-solid fa-fingerprint text-green-500 text-xs"></i>
          </div>
          <div className="bg-[#1A1D24] p-6 rounded-3xl border border-gray-800 shadow-xl flex flex-col items-center">
             <div 
               onClick={() => fileInputRef.current?.click()}
               className="relative w-24 h-24 rounded-[2rem] bg-gray-800 border-2 border-dashed border-gray-700 flex items-center justify-center cursor-pointer hover:border-[#D32F2F] transition-all overflow-hidden group"
             >
                {user.profilePic ? (
                  <img src={user.profilePic} alt="Profile" className="w-full h-full object-cover group-hover:opacity-40 transition-opacity" />
                ) : (
                  <span className="text-gray-500 font-black text-xl group-hover:opacity-20 transition-opacity">{userInitials}</span>
                )}
                <div className="absolute inset-0 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity bg-[#D32F2F]/20">
                   <i className="fa-solid fa-camera text-white"></i>
                </div>
                <input 
                  type="file" 
                  ref={fileInputRef} 
                  className="hidden" 
                  accept="image/*" 
                  onChange={handleImageUpload}
                />
             </div>
             <p className="text-[9px] text-gray-600 mt-4 font-black uppercase tracking-widest">Tap to update operative visualization</p>

             <div className="w-full mt-6 space-y-3">
                <div className="bg-black/30 p-4 rounded-2xl border border-white/5">
                   <p className="text-[8px] text-gray-500 font-black uppercase mb-1">Authenticated Operative</p>
                   <p className="text-white text-xs font-bold">{user.name}</p>
                </div>
                <div className="bg-black/30 p-4 rounded-2xl border border-white/5">
                   <p className="text-[8px] text-gray-500 font-black uppercase mb-1">Verified Comms</p>
                   <p className="text-white text-xs font-mono">{user.phone}</p>
                </div>
             </div>
          </div>
        </section>

        {/* Keyword Setting */}
        <section>
          <div className="flex justify-between items-center mb-4">
             <h3 className="text-[10px] text-gray-500 uppercase font-black tracking-widest">Voice Protocol</h3>
             <i className="fa-solid fa-microphone text-red-500 text-xs animate-pulse"></i>
          </div>
          <div className="bg-[#1A1D24] p-5 rounded-3xl border border-gray-800 shadow-xl">
            <p className="text-[10px] text-gray-500 mb-4 leading-relaxed font-medium uppercase tracking-tighter">Enter a custom cipher. System will initialize SOS sequence upon matching audio detection.</p>
            <div className="flex gap-2">
              <input 
                value={keyword}
                onChange={(e) => setKeyword(e.target.value.toUpperCase())}
                className="flex-1 bg-black/40 border border-gray-700 rounded-2xl p-4 text-white font-mono tracking-[0.3em] text-lg focus:outline-none focus:border-[#D32F2F]"
                placeholder="CIPHER"
              />
              <button 
                onClick={saveKeyword}
                className="bg-[#D32F2F] text-white px-6 rounded-2xl font-black text-[10px] uppercase tracking-widest shadow-lg shadow-red-900/20 active:scale-95 transition-all"
              >
                Sync
              </button>
            </div>
          </div>
        </section>

        {/* Contacts Section */}
        <section>
          <div className="flex justify-between items-center mb-4">
             <h3 className="text-[10px] text-gray-500 uppercase font-black tracking-widest">Response Network ({contacts.length}/5)</h3>
             <i className="fa-solid fa-users-viewfinder text-blue-500 text-xs"></i>
          </div>

          <div className="space-y-3 mb-6">
            {contacts.map(contact => (
              <div key={contact.contactId} className="bg-[#1A1D24] p-5 rounded-3xl border border-gray-800 flex justify-between items-center group">
                <div className="flex items-center gap-4">
                  <div className="w-11 h-11 rounded-2xl bg-gray-800 flex items-center justify-center border border-white/5">
                    <i className="fa-solid fa-user-shield text-[#D32F2F] text-sm"></i>
                  </div>
                  <div>
                    <h4 className="text-xs font-black text-white uppercase tracking-tight">{contact.name}</h4>
                    <p className="text-[10px] text-gray-600 font-mono mt-1">{contact.phone}</p>
                  </div>
                </div>
                <button onClick={() => deleteContact(contact.contactId)} className="w-8 h-8 rounded-lg bg-red-500/10 text-red-500/50 hover:text-red-500 transition-colors">
                  <i className="fa-solid fa-trash-can text-xs"></i>
                </button>
              </div>
            ))}

            {contacts.length === 0 && (
              <div className="bg-[#1A1D24] border-2 border-dashed border-gray-800 rounded-3xl p-8 flex flex-col items-center opacity-40">
                <i className="fa-solid fa-user-plus text-3xl mb-3 text-gray-600"></i>
                <p className="text-[10px] font-black uppercase text-gray-600">No Trust Ties Established</p>
              </div>
            )}
          </div>

          <div className="bg-[#1A1D24] p-6 rounded-[2.5rem] border border-gray-800 shadow-2xl">
             <p className="text-[10px] text-gray-500 uppercase font-black tracking-widest mb-4">Initialize New Tie</p>
             <div className="space-y-3">
                <input 
                  placeholder="Operative Name"
                  value={newContact.name}
                  onChange={(e) => setNewContact({...newContact, name: e.target.value})}
                  className="w-full bg-black/40 border border-gray-700 rounded-2xl p-4 text-white text-xs font-bold placeholder:text-gray-700 focus:outline-none"
                />
                <input 
                  placeholder="Comms Number"
                  value={newContact.phone}
                  onChange={(e) => setNewContact({...newContact, phone: e.target.value})}
                  className="w-full bg-black/40 border border-gray-700 rounded-2xl p-4 text-white text-xs font-mono placeholder:text-gray-700 focus:outline-none"
                />
                <button 
                  onClick={addContact}
                  className="w-full bg-gray-800 text-white font-black py-4 rounded-2xl text-[10px] uppercase tracking-[0.2em] shadow-lg active:scale-95 transition-all mt-2"
                >
                  Verify and Add
                </button>
             </div>
          </div>
        </section>

        <section className="bg-blue-500/10 border border-blue-500/20 p-5 rounded-3xl">
           <div className="flex gap-4">
              <i className="fa-solid fa-circle-info text-blue-500 mt-0.5"></i>
              <div>
                 <h4 className="text-[10px] font-black text-blue-500 uppercase tracking-widest mb-1">Responder Tip</h4>
                 <p className="text-[10px] text-gray-500 leading-relaxed font-medium">Your trusted contacts can access the <b>Responder Hub</b> to see your live coordinates and manually mark you as safe if you are unable to.</p>
              </div>
           </div>
        </section>
      </div>
    </div>
  );
};

export default SettingsScreen;

import React, { useState, useEffect, useRef } from 'react';
import { EmergencyRecord, LocationUpdate, EmergencyStatus, UserProfile } from '../types';
import { firebaseService } from '../firebase';

declare const L: any;

interface TrustedContactViewProps {
  onBack: () => void;
}

const TrustedContactView: React.FC<TrustedContactViewProps> = ({ onBack }) => {
  const [activeEmergencies, setActiveEmergencies] = useState<EmergencyRecord[]>([]);
  const [selectedId, setSelectedId] = useState<string | null>(null);
  const [locations, setLocations] = useState<LocationUpdate[]>([]);
  const [confirmSafeId, setConfirmSafeId] = useState<string | null>(null);
  const mapRef = useRef<any>(null);
  const markersRef = useRef<{ [key: string]: any }>({});
  const pathRef = useRef<any>(null);

  const refreshEmergencies = () => {
    const active = firebaseService.getAllActiveEmergencies();
    setActiveEmergencies(active);
    if (active.length > 0 && !selectedId) {
      setSelectedId(active[0].emergencyId);
    }
  };

  useEffect(() => {
    refreshEmergencies();
    const interval = setInterval(refreshEmergencies, 5000);
    window.addEventListener('storage_update', refreshEmergencies);
    return () => {
      clearInterval(interval);
      window.removeEventListener('storage_update', refreshEmergencies);
    };
  }, []);

  useEffect(() => {
    // Map setup
    if (!mapRef.current) {
      mapRef.current = L.map('responder-map', {
        zoomControl: false,
        attributionControl: false
      }).setView([20, 0], 2);

      L.tileLayer('https://{s}.basemaps.cartocdn.com/dark_all/{z}/{x}/{y}{r}.png', {
        maxZoom: 19
      }).addTo(mapRef.current);

      pathRef.current = L.polyline([], { color: '#D32F2F', weight: 4, opacity: 0.6 }).addTo(mapRef.current);
    }
  }, []);

  useEffect(() => {
    if (selectedId) {
      const locs = firebaseService.getEmergencyLocations(selectedId);
      setLocations(locs);

      if (locs.length > 0 && mapRef.current) {
        const latest = locs[locs.length - 1];
        const latlng = [latest.latitude, latest.longitude];

        mapRef.current.setView(latlng, 16);

        // Update marker
        if (markersRef.current[selectedId]) {
          markersRef.current[selectedId].setLatLng(latlng);
        } else {
          const icon = L.divIcon({
            className: 'responder-icon',
            html: `<div class="relative">
                    <div class="absolute -inset-4 w-12 h-12 bg-red-500/30 rounded-full animate-ping"></div>
                    <div class="w-6 h-6 bg-red-600 rounded-full border-2 border-white flex items-center justify-center">
                       <i class="fa-solid fa-person text-white text-[10px]"></i>
                    </div>
                   </div>`,
            iconSize: [24, 24],
            iconAnchor: [12, 12]
          });
          markersRef.current[selectedId] = L.marker(latlng, { icon }).addTo(mapRef.current);
        }

        // Update path
        if (pathRef.current) {
          pathRef.current.setLatLngs(locs.map(l => [l.latitude, l.longitude]));
        }
      }
    }
  }, [selectedId, locations.length]);

  const handleRemoteTrigger = () => {
    const db = JSON.parse(localStorage.getItem('SAFE_VOICE_DB') || '{}');
    const firstUserId = (Object.values(db.users || {}) as UserProfile[])[0]?.userId;
    if (firstUserId) {
      firebaseService.triggerEmergency(firstUserId);
      refreshEmergencies();
    } else {
      alert("No registered users found to protect. Please sign up first.");
    }
  };

  const handleSafe = (id: string) => {
    firebaseService.resolveEmergency(id);
    if (markersRef.current[id]) {
      mapRef.current.removeLayer(markersRef.current[id]);
      delete markersRef.current[id];
    }
    refreshEmergencies();
    setSelectedId(null);
    setConfirmSafeId(null);
  };

  return (
    <div className="flex flex-col h-full w-full bg-[#0F1115]">
      {/* Dashboard Header */}
      <div className="p-6 pt-10 bg-[#1A1D24] border-b border-gray-800 shadow-xl flex items-center justify-between z-20">
        <div className="flex items-center gap-3">
          <button onClick={onBack} className="w-10 h-10 rounded-xl bg-gray-800/50 flex items-center justify-center text-gray-400 hover:text-white transition-all">
            <i className="fa-solid fa-arrow-left"></i>
          </button>
          <div>
            <h2 className="text-sm font-black text-white uppercase tracking-widest leading-none">Responder Hub</h2>
            <span className="text-[9px] text-blue-400 font-bold uppercase tracking-tighter block mt-1">Live Sentinel Monitoring</span>
          </div>
        </div>
        <div className="flex items-center gap-2">
           <div className="w-2 h-2 rounded-full bg-blue-500 animate-pulse"></div>
           <span className="text-[10px] text-gray-500 font-black">SYSTEM LIVE</span>
        </div>
      </div>

      {/* Main Tracking Area */}
      <div className="flex-1 relative">
        <div id="responder-map" className="absolute inset-0 z-0 bg-gray-900"></div>

        {/* Overlay Controls */}
        <div className="absolute top-4 right-4 z-10 flex flex-col gap-2">
           <button 
             onClick={handleRemoteTrigger}
             className="bg-[#D32F2F] text-white p-4 rounded-2xl shadow-2xl flex items-center gap-2 font-black text-xs uppercase tracking-widest animate-pulse pointer-events-auto transition-transform active:scale-90"
           >
             <i className="fa-solid fa-tower-broadcast"></i>
             Remote Alert
           </button>
        </div>

        {/* Selected User Data */}
        {selectedId && (
           <div className="absolute bottom-24 left-4 right-4 z-10 bg-[#1A1D24]/90 backdrop-blur-xl border border-white/10 rounded-[2rem] p-5 shadow-2xl pointer-events-auto">
              <div className="flex justify-between items-start mb-4">
                 <div>
                    <h3 className="text-white font-black text-sm uppercase tracking-wider">User Tracking Active</h3>
                    <p className="text-gray-500 text-[9px] font-bold uppercase tracking-tighter mt-1">
                       Emerg ID: {selectedId.substr(-8)} • {locations.length} Packets Received
                    </p>
                 </div>
                 <button 
                   onClick={() => setConfirmSafeId(selectedId)}
                   className="bg-green-600 text-white px-4 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest shadow-lg shadow-green-900/20 active:scale-95 transition-all"
                 >
                   Clear Alert
                 </button>
              </div>
              <div className="grid grid-cols-2 gap-4">
                 <div className="bg-black/30 p-3 rounded-xl border border-white/5">
                    <p className="text-[8px] text-gray-500 font-black uppercase">Latitude</p>
                    <p className="text-white font-mono text-xs">{locations[locations.length-1]?.latitude.toFixed(6) || '---'}</p>
                 </div>
                 <div className="bg-black/30 p-3 rounded-xl border border-white/5">
                    <p className="text-[8px] text-gray-500 font-black uppercase">Longitude</p>
                    <p className="text-white font-mono text-xs">{locations[locations.length-1]?.longitude.toFixed(6) || '---'}</p>
                 </div>
              </div>
           </div>
        )}
      </div>

      {/* Responder List Panel */}
      <div className="bg-[#1A1D24] p-6 pb-10 rounded-t-[3rem] border-t border-gray-800 z-20 max-h-[300px] overflow-y-auto">
         <h4 className="text-[10px] text-gray-500 font-black uppercase tracking-[0.2em] mb-4 flex items-center gap-2">
            <i className="fa-solid fa-list-check"></i>
            Active Alerts Queue
         </h4>

         {activeEmergencies.length === 0 ? (
            <div className="flex flex-col items-center justify-center py-8 text-center opacity-40">
               <i className="fa-solid fa-shield-halved text-4xl mb-3 text-gray-600"></i>
               <p className="text-xs font-bold text-gray-600 uppercase">No active distress signals</p>
            </div>
         ) : (
            <div className="space-y-3">
               {activeEmergencies.map(e => (
                  <div 
                    key={e.emergencyId}
                    onClick={() => setSelectedId(e.emergencyId)}
                    className={`p-4 rounded-2xl border transition-all cursor-pointer flex justify-between items-center ${selectedId === e.emergencyId ? 'bg-red-900/20 border-red-500/50' : 'bg-gray-900 border-gray-800'}`}
                  >
                     <div className="flex items-center gap-3">
                        <div className="w-10 h-10 rounded-xl bg-red-600/10 flex items-center justify-center border border-red-600/30">
                           <i className="fa-solid fa-person-running text-red-500"></i>
                        </div>
                        <div>
                           <p className="text-white text-xs font-bold uppercase tracking-tight">Active SOS: {e.userId.substr(0,8)}</p>
                           <p className="text-gray-500 text-[8px] font-black uppercase mt-1">Broadcast start: {new Date(e.triggeredAt).toLocaleTimeString()}</p>
                        </div>
                     </div>
                     <i className="fa-solid fa-chevron-right text-gray-700"></i>
                  </div>
               ))}
            </div>
         )}
      </div>

      {/* Confirmation Modal */}
      {confirmSafeId && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-6 bg-black/60 backdrop-blur-sm animate-fade-in">
          <div className="bg-[#1A1D24] border border-white/10 w-full max-w-sm rounded-[2.5rem] p-8 shadow-[0_25px_100px_rgba(0,0,0,0.9)] animate-scale-in">
            <div className="w-16 h-16 bg-green-500/10 rounded-full flex items-center justify-center mx-auto mb-6 border border-green-500/20">
              <i className="fa-solid fa-shield-check text-green-500 text-3xl"></i>
            </div>
            <h3 className="text-xl font-black text-white text-center uppercase tracking-widest mb-3">Confirm Resolution?</h3>
            <p className="text-gray-500 text-[10px] text-center font-black uppercase tracking-[0.2em] leading-relaxed mb-8">
              Are you certain this operative is now in a secure state? Marking as safe will terminate live tracking and notify all nodes.
            </p>
            <div className="flex flex-col gap-3">
              <button 
                onClick={() => handleSafe(confirmSafeId)}
                className="w-full bg-green-600 text-white font-black py-4 rounded-2xl uppercase tracking-[0.25em] shadow-xl shadow-green-900/20 active:scale-95 transition-all text-sm"
              >
                Confirm Secure
              </button>
              <button 
                onClick={() => setConfirmSafeId(null)}
                className="w-full bg-gray-800 text-gray-400 font-black py-4 rounded-2xl uppercase tracking-[0.2em] active:scale-95 transition-all text-[10px] border border-white/5"
              >
                Abort & Continue Tracking
              </button>
            </div>
          </div>
        </div>
      )}

      <style>{`
        @keyframes fadeIn {
          from { opacity: 0; }
          to { opacity: 1; }
        }
        @keyframes scaleIn {
          from { transform: scale(0.9); opacity: 0; }
          to { transform: scale(1); opacity: 1; }
        }
        .animate-fade-in { animation: fadeIn 0.3s ease-out forwards; }
        .animate-scale-in { animation: scaleIn 0.3s cubic-bezier(0.34, 1.56, 0.64, 1) forwards; }
      `}</style>
    </div>
  );
};

export default TrustedContactView;

import { UserProfile, Contact, EmergencyRecord, LocationUpdate, EmergencyStatus } from './types';

const STORAGE_KEY = 'SAFE_VOICE_DB';

const getDB = () => {
  const data = localStorage.getItem(STORAGE_KEY);
  return data ? JSON.parse(data) : { users: {}, contacts: [], emergencies: [], locations: [] };
};

const saveDB = (db: any) => {
  localStorage.setItem(STORAGE_KEY, JSON.stringify(db));
  window.dispatchEvent(new Event('storage_update'));
};

export const firebaseService = {
  // AUTHENTICATION
  getCurrentUser: (): UserProfile | null => {
    const userJson = localStorage.getItem('SAFE_VOICE_SESSION');
    return userJson ? JSON.parse(userJson) : null;
  },

  signUp: async (name: string, email: string, phone: string): Promise<UserProfile> => {
    const db = getDB();
    const emailKey = email.toLowerCase();
    if (db.users[emailKey]) throw new Error("Account exists.");
    const user: UserProfile = {
      userId: 'u_' + Math.random().toString(36).substr(2, 9),
      name, email: emailKey, phone,
      emergencyKeyword: 'HELP', isArmed: false, createdAt: Date.now()
    };
    db.users[emailKey] = user;
    saveDB(db);
    localStorage.setItem('SAFE_VOICE_SESSION', JSON.stringify(user));
    return user;
  },

  login: async (email: string): Promise<UserProfile> => {
    const db = getDB();
    const user = db.users[email.toLowerCase()] as UserProfile;
    if (!user) throw new Error("Access Denied.");
    localStorage.setItem('SAFE_VOICE_SESSION', JSON.stringify(user));
    return user;
  },

  logout: () => localStorage.removeItem('SAFE_VOICE_SESSION'),

  updateProfile: (userId: string, updates: Partial<UserProfile>) => {
    const db = getDB();
    const emailKey = Object.keys(db.users).find(key => db.users[key].userId === userId);
    if (emailKey) {
      db.users[emailKey] = { ...db.users[emailKey], ...updates };
      saveDB(db);
      localStorage.setItem('SAFE_VOICE_SESSION', JSON.stringify(db.users[emailKey]));
    }
  },

  // CONTACTS & MONITORING
  getContacts: (userId: string): Contact[] => {
    return getDB().contacts.filter((c: Contact) => c.userId === userId);
  },

  addContact: (contact: Contact) => {
    const db = getDB();
    db.contacts.push(contact);
    saveDB(db);
  },

  // EMERGENCY CORE
  triggerEmergency: (userId: string): string => {
    const db = getDB();
    const existing = db.emergencies.find((e: any) => e.userId === userId && e.status === EmergencyStatus.ACTIVE);
    if (existing) return existing.emergencyId;

    const emergencyId = 'e_' + Date.now();
    const record: EmergencyRecord = { emergencyId, userId, status: EmergencyStatus.ACTIVE, triggeredAt: Date.now() };
    db.emergencies.push(record);
    saveDB(db);

    // Simulate FCM/SMS Notification
    console.log(`%c[FCM BROADCAST] High Priority SOS Sent for ${userId}`, 'background: #D32F2F; color: white; padding: 5px;');
    return emergencyId;
  },

  resolveEmergency: (emergencyId: string) => {
    const db = getDB();
    const record = db.emergencies.find((e: EmergencyRecord) => e.emergencyId === emergencyId);
    if (record) {
      record.status = EmergencyStatus.SAFE;
      record.resolvedAt = Date.now();
      saveDB(db);
    }
  },

  getAllActiveEmergencies: (): EmergencyRecord[] => {
    return getDB().emergencies.filter((e: EmergencyRecord) => e.status === EmergencyStatus.ACTIVE);
  },

  // GET VICTIM DETAILS
  getUserById: (userId: string): UserProfile | undefined => {
    const db = getDB();
    return Object.values(db.users).find((u: any) => u.userId === userId) as UserProfile;
  },

  // LOCATION CORE
  pushLocation: (location: LocationUpdate) => {
    const db = getDB();
    db.locations.push(location);
    saveDB(db);
  },

  getEmergencyLocations: (emergencyId: string): LocationUpdate[] => {
    return getDB().locations.filter((l: LocationUpdate) => l.emergencyId === emergencyId);
  }
};

import React, { useState, useEffect, useRef } from 'react';
import { EmergencyRecord, LocationUpdate, EmergencyStatus, UserProfile } from '../types';
import { firebaseService } from '../firebase';

declare const L: any;

interface TrustedContactViewProps {
  onBack: () => void;
}

const TrustedContactView: React.FC<TrustedContactViewProps> = ({ onBack }) => {
  const [activeEmergencies, setActiveEmergencies] = useState<EmergencyRecord[]>([]);
  const [selectedEmergency, setSelectedEmergency] = useState<EmergencyRecord | null>(null);
  const [victimProfile, setVictimProfile] = useState<UserProfile | null>(null);
  const [locations, setLocations] = useState<LocationUpdate[]>([]);
  const [confirmSafeId, setConfirmSafeId] = useState<string | null>(null);

  const mapRef = useRef<any>(null);
  const markerRef = useRef<any>(null);
  const pathRef = useRef<any>(null);

  const refreshData = () => {
    const active = firebaseService.getAllActiveEmergencies();
    setActiveEmergencies(active);

    if (active.length > 0 && !selectedEmergency) {
      handleSelectEmergency(active[0]);
    } else if (selectedEmergency) {
      // Refresh current selected emergency tracking
      const updated = active.find(e => e.emergencyId === selectedEmergency.emergencyId);
      if (updated) {
        const locs = firebaseService.getEmergencyLocations(updated.emergencyId);
        setLocations(locs);
        updateMap(locs);
      } else {
        setSelectedEmergency(null);
        setVictimProfile(null);
      }
    }
  };

  const handleSelectEmergency = (e: EmergencyRecord) => {
    setSelectedEmergency(e);
    setVictimProfile(firebaseService.getUserById(e.userId) || null);
    const locs = firebaseService.getEmergencyLocations(e.emergencyId);
    setLocations(locs);
    updateMap(locs);
  };

  const updateMap = (locs: LocationUpdate[]) => {
    if (!mapRef.current || locs.length === 0) return;
    const latest = locs[locs.length - 1];
    const latlng = [latest.latitude, latest.longitude];

    mapRef.current.setView(latlng, 17);

    if (markerRef.current) {
      markerRef.current.setLatLng(latlng);
    } else {
      const icon = L.divIcon({
        className: 'pulse-icon',
        html: `<div class="relative">
                <div class="absolute -inset-6 w-16 h-16 bg-red-600/20 rounded-full animate-ping"></div>
                <div class="w-8 h-8 bg-red-600 rounded-full border-2 border-white flex items-center justify-center shadow-2xl">
                  <i class="fa-solid fa-person-walking-exclamation text-white text-sm"></i>
                </div>
               </div>`,
        iconSize: [32, 32],
        iconAnchor: [16, 16]
      });
      markerRef.current = L.marker(latlng, { icon }).addTo(mapRef.current);
    }

    if (pathRef.current) {
      pathRef.current.setLatLngs(locs.map(l => [l.latitude, l.longitude]));
    }
  };

  useEffect(() => {
    if (!mapRef.current) {
      mapRef.current = L.map('command-map', { zoomControl: false, attributionControl: false }).setView([20, 0], 2);
      L.tileLayer('https://{s}.basemaps.cartocdn.com/dark_all/{z}/{x}/{y}{r}.png', { maxZoom: 20 }).addTo(mapRef.current);
      pathRef.current = L.polyline([], { color: '#D32F2F', weight: 5, opacity: 0.8 }).addTo(mapRef.current);
    }

    refreshData();
    const interval = setInterval(refreshData, 3000);
    window.addEventListener('storage_update', refreshData);

    return () => {
      clearInterval(interval);
      window.removeEventListener('storage_update', refreshData);
      if (mapRef.current) mapRef.current.remove();
    };
  }, []);

  const handleRemoteAlert = () => {
    // Demonstrating the ability to trigger alert for a simulated user
    const db = JSON.parse(localStorage.getItem('SAFE_VOICE_DB') || '{}');
    const victim = Object.values(db.users || {})[0] as UserProfile;
    if (victim) {
      firebaseService.triggerEmergency(victim.userId);
      refreshData();
    } else {
      alert("No protected users registered in database.");
    }
  };

  const resolveAlert = (id: string) => {
    firebaseService.resolveEmergency(id);
    if (markerRef.current) {
      mapRef.current.removeLayer(markerRef.current);
      markerRef.current = null;
    }
    setConfirmSafeId(null);
    refreshData();
  };

  return (
    <div className="flex flex-col h-full w-full bg-[#090B0E] text-white">
      {/* HUD Header */}
      <div className="p-6 pt-10 bg-[#12151A] border-b border-gray-800 flex items-center justify-between z-20 shadow-2xl">
        <div className="flex items-center gap-4">
          <button onClick={onBack} className="w-10 h-10 rounded-xl bg-gray-800/50 flex items-center justify-center text-gray-400 hover:text-white border border-white/5 transition-all active:scale-90">
            <i className="fa-solid fa-chevron-left"></i>
          </button>
          <div>
            <h2 className="text-xs font-black uppercase tracking-[0.3em] text-blue-500">Sentinel Hub</h2>
            <p className="text-[10px] font-bold text-gray-500 uppercase mt-0.5">Tactical Monitoring Active</p>
          </div>
        </div>
        <div className="flex flex-col items-end">
          <div className="flex items-center gap-2">
            <span className="w-1.5 h-1.5 rounded-full bg-green-500 animate-pulse"></span>
            <span className="text-[10px] font-black uppercase tracking-widest text-gray-400">Live Uplink</span>
          </div>
          <p className="text-[8px] font-mono text-gray-600 mt-1">NODE: SV-TACT-09</p>
        </div>
      </div>

      {/* Primary Monitor Map */}
      <div className="flex-1 relative">
        <div id="command-map" className="absolute inset-0 z-0 grayscale-[0.2] brightness-[0.8]"></div>

        {/* Remote SOS Tool */}
        <div className="absolute top-4 right-4 z-10">
          <button 
            onClick={handleRemoteAlert}
            className="bg-[#D32F2F] text-white px-6 py-4 rounded-2xl shadow-[0_10px_40px_rgba(211,47,47,0.4)] flex items-center gap-3 font-black text-[10px] uppercase tracking-[0.2em] animate-pulse active:scale-95 transition-all"
          >
            <i className="fa-solid fa-tower-broadcast text-lg"></i>
            Sentinel Broadcast
          </button>
        </div>

        {/* Selected Victim Telemetry Card */}
        {selectedEmergency && victimProfile && (
          <div className="absolute bottom-6 left-4 right-4 z-10 bg-[#12151A]/95 backdrop-blur-3xl border border-white/10 rounded-[2.5rem] p-6 shadow-[0_30px_90px_rgba(0,0,0,0.8)] animate-slide-up">
            <div className="flex justify-between items-start mb-6">
              <div className="flex items-center gap-4">
                <div className="w-14 h-14 rounded-2xl bg-red-600/10 border border-red-600/30 flex items-center justify-center overflow-hidden">
                  {victimProfile.profilePic ? (
                    <img src={victimProfile.profilePic} className="w-full h-full object-cover" />
                  ) : (
                    <i className="fa-solid fa-user-ninja text-red-500 text-2xl"></i>
                  )}
                </div>
                <div>
                  <h3 className="text-white font-black text-sm uppercase tracking-wider">{victimProfile.name}</h3>
                  <div className="flex items-center gap-2 mt-1">
                    <div className="w-2 h-2 rounded-full bg-red-500 animate-pulse"></div>
                    <p className="text-[9px] text-red-500 font-black uppercase tracking-tighter">Emergency Protocol: ACTIVE</p>
                  </div>
                </div>
              </div>
              <button 
                onClick={() => setConfirmSafeId(selectedEmergency.emergencyId)}
                className="bg-green-600 hover:bg-green-500 text-white px-5 py-2.5 rounded-xl text-[10px] font-black uppercase tracking-widest shadow-xl transition-all active:scale-90"
              >
                Clear Node
              </button>
            </div>

            <div className="grid grid-cols-2 gap-4">
              <div className="bg-black/40 border border-white/5 p-4 rounded-2xl">
                <p className="text-[8px] text-gray-500 font-black uppercase mb-1">Last Coordinates</p>
                <p className="text-white font-mono text-[11px] font-bold">
                  {locations[locations.length-1]?.latitude.toFixed(6)}, {locations[locations.length-1]?.longitude.toFixed(6)}
                </p>
              </div>
              <div className="bg-black/40 border border-white/5 p-4 rounded-2xl">
                <p className="text-[8px] text-gray-500 font-black uppercase mb-1">Signal Latency</p>
                <p className="text-blue-400 font-mono text-[11px] font-bold">128ms / CLEAR</p>
              </div>
            </div>
          </div>
        )}
      </div>

      {/* Active Alerts Sidebar/Footer */}
      <div className="p-6 pb-12 bg-[#12151A] border-t border-gray-800 z-20 max-h-[280px] overflow-y-auto rounded-t-[3.5rem] shadow-[0_-20px_60px_rgba(0,0,0,0.5)]">
        <div className="flex items-center justify-between mb-6 px-2">
          <h4 className="text-[10px] text-gray-500 font-black uppercase tracking-[0.25em] flex items-center gap-2">
            <i className="fa-solid fa-satellite-dish text-blue-500"></i>
            Active Distress Signals
          </h4>
          <span className="text-[10px] font-black bg-gray-900 border border-white/5 px-3 py-1 rounded-full text-gray-400">
            {activeEmergencies.length} NODES
          </span>
        </div>

        {activeEmergencies.length === 0 ? (
          <div className="flex flex-col items-center justify-center py-12 text-center opacity-30">
            <i className="fa-solid fa-shield-virus text-5xl mb-4 text-gray-700"></i>
            <p className="text-[10px] font-black uppercase tracking-widest text-gray-600 leading-relaxed">
              Global Perimeter Secure<br/>No Active Signals Detected
            </p>
          </div>
        ) : (
          <div className="space-y-4">
            {activeEmergencies.map(e => (
              <div 
                key={e.emergencyId}
                onClick={() => handleSelectEmergency(e)}
                className={`p-5 rounded-[2rem] border-2 transition-all cursor-pointer flex justify-between items-center group ${selectedEmergency?.emergencyId === e.emergencyId ? 'bg-red-950/20 border-red-600/50 shadow-inner' : 'bg-gray-900 border-gray-800'}`}
              >
                <div className="flex items-center gap-4">
                  <div className="w-12 h-12 rounded-2xl bg-red-600/10 flex items-center justify-center border border-red-600/20 group-hover:scale-110 transition-transform">
                    <i className="fa-solid fa-person-running text-red-500 text-xl animate-pulse"></i>
                  </div>
                  <div>
                    <p className="text-white text-xs font-black uppercase tracking-tight">Signal: {e.userId.substr(0,8).toUpperCase()}</p>
                    <p className="text-gray-500 text-[8px] font-black uppercase mt-1 tracking-tighter">Lock On: {new Date(e.triggeredAt).toLocaleTimeString()}</p>
                  </div>
                </div>
                <div className="w-10 h-10 rounded-xl bg-gray-800/50 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity">
                  <i className="fa-solid fa-crosshairs text-blue-500 text-sm"></i>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>

      {/* Confirmation Modal */}
      {confirmSafeId && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-8 bg-black/80 backdrop-blur-md">
          <div className="bg-[#12151A] border border-white/10 w-full max-w-sm rounded-[3rem] p-10 shadow-[0_30px_100px_rgba(0,0,0,1)] text-center scale-up-center">
            <div className="w-20 h-20 bg-green-500/10 rounded-full flex items-center justify-center mx-auto mb-8 border border-green-500/20 animate-pulse">
              <i className="fa-solid fa-shield-check text-green-500 text-4xl"></i>
            </div>
            <h3 className="text-xl font-black text-white uppercase tracking-[0.2em] mb-4 leading-tight">Secure Perimeters?</h3>
            <p className="text-gray-500 text-[10px] font-black uppercase tracking-[0.2em] leading-relaxed mb-10">
              Confirm victim status as "SECURE" to terminate the live coordinate broadcast and close the tactical node.
            </p>
            <div className="flex flex-col gap-4">
              <button 
                onClick={() => resolveAlert(confirmSafeId)}
                className="w-full bg-green-600 text-white font-black py-5 rounded-2xl uppercase tracking-[0.3em] shadow-2xl active:scale-95 transition-all text-xs"
              >
                Authorize Close
              </button>
              <button 
                onClick={() => setConfirmSafeId(null)}
                className="w-full bg-transparent text-gray-600 font-black py-4 rounded-2xl uppercase tracking-[0.2em] active:scale-95 transition-all text-[9px]"
              >
                Abort & Continue Feed
              </button>
            </div>
          </div>
        </div>
      )}

      <style>{`
        @keyframes slideUp {
          from { transform: translateY(30px); opacity: 0; }
          to { transform: translateY(0); opacity: 1; }
        }
        .animate-slide-up { animation: slideUp 0.6s cubic-bezier(0.23, 1, 0.32, 1) forwards; }

        .scale-up-center { animation: scale-up-center 0.4s cubic-bezier(0.390, 0.575, 0.565, 1.000) both; }
        @keyframes scale-up-center {
          0% { transform: scale(0.5); opacity: 0; }
          100% { transform: scale(1); opacity: 1; }
        }
      `}</style>
    </div>
  );
};

