rules_version = '2';
service cloud.firestore {
  match /databases/{database}/documents {

    // Helper to check if user is a trusted contact
    function isTrustedContact(userId) {
      return exists(/databases/$(database)/documents/contacts/$(request.auth.uid + '_' + userId));
    }

    match /users/{userId} {
      allow read, write: if request.auth != null && request.auth.uid == userId;
    }

    match /contacts/{contactId} {
      allow read, write: if request.auth != null && (resource.data.ownerUserId == request.auth.uid || resource.data.contactId == request.auth.uid);
    }

    match /emergencies/{emergencyId} {
      allow create: if request.auth != null;
      allow read, update: if request.auth != null && (
        resource.data.userId == request.auth.uid || 
        isTrustedContact(resource.data.userId)
      );
    }

    match /locations/{locationId} {
      // High-precision tracking data only visible to the victim or their trusted responders
      allow create: if request.auth != null;
      allow read: if request.auth != null && (
        get(/databases/$(database)/documents/emergencies/$(resource.data.emergencyId)).data.userId == request.auth.uid ||
        isTrustedContact(get(/databases/$(database)/documents/emergencies/$(resource.data.emergencyId)).data.userId)
      );
    }
  }
}

const functions = require('firebase-functions');
const admin = require('firebase-admin');
admin.initializeApp();

/**
 * Triggered when a new SOS record is initialized.
 * Dispatches high-priority data messages to all verified contacts.
 */
exports.onEmergencyTriggered = functions.firestore
  .document('emergencies/{emergencyId}')
  .onCreate(async (snapshot, context) => {
    const data = snapshot.data();
    if (data.status !== 'ACTIVE') return null;

    const victimId = data.userId;
    const emergencyId = context.params.emergencyId;

    // 1. Fetch victim details
    const victimDoc = await admin.firestore().collection('users').doc(victimId).get();
    const victimName = victimDoc.exists ? victimDoc.data().name : "An Operative";

    // 2. Fetch all trusted contact tokens
    const contactsSnapshot = await admin.firestore()
      .collection('contacts')
      .where('ownerUserId', '==', victimId)
      .get();

    const tokens = [];
    contactsSnapshot.forEach(doc => {
      const contactData = doc.data();
      if (contactData.fcmToken) {
        tokens.push(contactData.fcmToken);
      }
    });

    if (tokens.length === 0) {
      console.log(`No registered contacts for victim: ${victimId}`);
      return null;
    }

    // 3. Construct High-Priority Payload
    const message = {
      notification: {
        title: '🚨 EMERGENCY ALERT: SAFE-VOICE',
        body: `${victimName} has triggered an SOS. Tap to begin tactical intercept.`,
      },
      data: {
        type: 'EMERGENCY_START',
        emergencyId: emergencyId,
        victimId: victimId,
        click_action: 'FLUTTER_NOTIFICATION_CLICK' // Direct intent to tracking screen
      },
      android: {
        priority: 'high',
        notification: {
          channelId: 'emergency_channel',
          sound: 'critical_alert.mp3',
          icon: 'ic_sos_alert'
        }
      },
      tokens: tokens,
    };

    // 4. Dispatch Multi-cast
    try {
      const response = await admin.messaging().sendMulticast(message);
      console.log(`SOS Dispatched: ${response.successCount} delivered, ${response.failureCount} failed.`);
      return response;
    } catch (error) {
      console.error('SOS BROADCAST FAILURE:', error);
      return null;
    }
  });

import { UserProfile, Contact, EmergencyRecord, LocationUpdate, EmergencyStatus } from './types';

const STORAGE_KEY = 'SAFE_VOICE_DB';

const getDB = () => {
  const data = localStorage.getItem(STORAGE_KEY);
  return data ? JSON.parse(data) : { users: {}, contacts: [], emergencies: [], locations: [] };
};

const saveDB = (db: any) => {
  localStorage.setItem(STORAGE_KEY, JSON.stringify(db));
  window.dispatchEvent(new Event('storage_update'));
};

export const firebaseService = {
  // AUTHENTICATION
  getCurrentUser: (): UserProfile | null => {
    const userJson = localStorage.getItem('SAFE_VOICE_SESSION');
    return userJson ? JSON.parse(userJson) : null;
  },

  signUp: async (name: string, email: string, phone: string): Promise<UserProfile> => {
    const db = getDB();
    const emailKey = email.toLowerCase();
    if (db.users[emailKey]) throw new Error("Account exists.");
    const user: UserProfile = {
      userId: 'u_' + Math.random().toString(36).substr(2, 9),
      name, email: emailKey, phone,
      emergencyKeyword: 'HELP', isArmed: false, createdAt: Date.now()
    };
    db.users[emailKey] = user;
    saveDB(db);
    localStorage.setItem('SAFE_VOICE_SESSION', JSON.stringify(user));
    return user;
  },

  login: async (email: string): Promise<UserProfile> => {
    const db = getDB();
    const user = db.users[email.toLowerCase()] as UserProfile;
    if (!user) throw new Error("Access Denied.");
    localStorage.setItem('SAFE_VOICE_SESSION', JSON.stringify(user));
    return user;
  },

  logout: () => localStorage.removeItem('SAFE_VOICE_SESSION'),

  updateProfile: (userId: string, updates: Partial<UserProfile>) => {
    const db = getDB();
    const emailKey = Object.keys(db.users).find(key => db.users[key].userId === userId);
    if (emailKey) {
      db.users[emailKey] = { ...db.users[emailKey], ...updates };
      saveDB(db);
      localStorage.setItem('SAFE_VOICE_SESSION', JSON.stringify(db.users[emailKey]));
    }
  },

  // CONTACTS & MONITORING
  getContacts: (userId: string): Contact[] => {
    return getDB().contacts.filter((c: Contact) => c.userId === userId);
  },

  addContact: (contact: Contact) => {
    const db = getDB();
    db.contacts.push(contact);
    saveDB(db);
  },

  // Added missing deleteContact method to fix error in SettingsScreen.tsx
  deleteContact: (contactId: string) => {
    const db = getDB();
    db.contacts = db.contacts.filter((c: Contact) => c.contactId !== contactId);
    saveDB(db);
  },

  // EMERGENCY CORE
  triggerEmergency: (userId: string): string => {
    const db = getDB();
    const existing = db.emergencies.find((e: any) => e.userId === userId && e.status === EmergencyStatus.ACTIVE);
    if (existing) return existing.emergencyId;

    const emergencyId = 'e_' + Date.now();
    const record: EmergencyRecord = { emergencyId, userId, status: EmergencyStatus.ACTIVE, triggeredAt: Date.now() };
    db.emergencies.push(record);
    saveDB(db);

    // Simulate FCM/SMS Notification
    console.log(`%c[FCM BROADCAST] High Priority SOS Sent for ${userId}`, 'background: #D32F2F; color: white; padding: 5px;');
    return emergencyId;
  },

  resolveEmergency: (emergencyId: string) => {
    const db = getDB();
    const record = db.emergencies.find((e: EmergencyRecord) => e.emergencyId === emergencyId);
    if (record) {
      record.status = EmergencyStatus.SAFE;
      record.resolvedAt = Date.now();
      saveDB(db);
    }
  },

  getAllActiveEmergencies: (): EmergencyRecord[] => {
    return getDB().emergencies.filter((e: EmergencyRecord) => e.status === EmergencyStatus.ACTIVE);
  },

  // Added missing getActiveEmergency method to fix error in App.tsx
  getActiveEmergency: (userId: string): EmergencyRecord | undefined => {
    return getDB().emergencies.find((e: EmergencyRecord) => e.userId === userId && e.status === EmergencyStatus.ACTIVE);
  },

  // GET VICTIM DETAILS
  getUserById: (userId: string): UserProfile | undefined => {
    const db = getDB();
    return Object.values(db.users).find((u: any) => u.userId === userId) as UserProfile;
  },

  // LOCATION CORE
  pushLocation: (location: LocationUpdate) => {
    const db = getDB();
    db.locations.push(location);
    saveDB(db);
  },

  getEmergencyLocations: (emergencyId: string): LocationUpdate[] => {
    return getDB().locations.filter((l: LocationUpdate) => l.emergencyId === emergencyId);
  }
};

const CACHE_NAME = 'safe-voice-v1';
const ASSETS = [
  '/',
  '/index.html',
  'https://cdn.tailwindcss.com',
  'https://cdnjs.cloudflare.com/ajax/libs/font-awesome/6.4.0/css/all.min.css',
  'https://unpkg.com/leaflet@1.9.4/dist/leaflet.css',
  'https://unpkg.com/leaflet@1.9.4/dist/leaflet.js'
];

self.addEventListener('install', (event) => {
  event.waitUntil(
    caches.open(CACHE_NAME).then((cache) => cache.addAll(ASSETS))
  );
});

self.addEventListener('fetch', (event) => {
  event.respondWith(
    caches.match(event.request).then((response) => {
      return response || fetch(event.request);
    })
  );
});

import React, { useState, useEffect, useRef } from 'react';
import { UserProfile, EmergencyRecord, LocationUpdate } from '../types';
import { firebaseService } from '../firebase';
import { GoogleGenAI } from "@google/genai";

declare const L: any;

interface EmergencyScreenProps {
  user: UserProfile;
  emergency: EmergencyRecord;
  onResolve: () => void;
}

const EmergencyScreen: React.FC<EmergencyScreenProps> = ({ user, emergency, onResolve }) => {
  const [locations, setLocations] = useState<LocationUpdate[]>([]);
  const [currentCoords, setCurrentCoords] = useState<{lat: number, lng: number} | null>(null);
  const [dispatchLogs, setDispatchLogs] = useState<string[]>([]);
  const [aiReport, setAiReport] = useState<string>("Initializing Safety Audit...");

  const mapRef = useRef<any>(null);
  const markerRef = useRef<any>(null);
  const pathRef = useRef<any>(null);
  const watchIdRef = useRef<number | null>(null);

  const addLog = (msg: string) => {
    const time = new Date().toLocaleTimeString();
    setDispatchLogs(prev => [`[${time}] ${msg}`, ...prev].slice(0, 5));
  };

  // Gemini Safety Auditor
  const runAiAudit = async (loc: LocationUpdate) => {
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `You are a professional security dispatcher. Audit the following safety data and provide a 1-sentence verification report: 
        Victim: ${user.name}, 
        Emergency ID: ${emergency.emergencyId}, 
        Current Coords: ${loc.latitude}, ${loc.longitude}, 
        Status: SOS ACTIVE. 
        Format: [SECURE LOG] {Report content}`
      });
      setAiReport(response.text || "Audit complete. Protocols verified.");
    } catch (e) {
      setAiReport("Audit link active. Monitoring coordinates...");
    }
  };

  useEffect(() => {
    addLog("System Initialized. SOS Broadcast start.");
    const contacts = firebaseService.getContacts(user.userId);
    contacts.forEach(c => addLog(`FCM PUSH: ALERT SENT TO ${c.name}`));

    const initMap = () => {
      const container = document.getElementById('map-container');
      if (container && !mapRef.current) {
        mapRef.current = L.map('map-container', {
          zoomControl: false,
          attributionControl: false
        }).setView([0, 0], 2);

        L.tileLayer('https://{s}.basemaps.cartocdn.com/dark_all/{z}/{x}/{y}{r}.png', { maxZoom: 19 }).addTo(mapRef.current);
        pathRef.current = L.polyline([], { color: '#D32F2F', weight: 4, opacity: 0.6 }).addTo(mapRef.current);
      }
    };

    const timer = setTimeout(initMap, 100);

    if ("geolocation" in navigator) {
      watchIdRef.current = navigator.geolocation.watchPosition(
        (position) => {
          const { latitude, longitude } = position.coords;
          const newLoc = { emergencyId: emergency.emergencyId, latitude, longitude, timestamp: Date.now() };

          firebaseService.pushLocation(newLoc);
          setCurrentCoords({ lat: latitude, lng: longitude });
          setLocations(prev => [...prev, newLoc]);
          addLog(`TX UPLINK: ${latitude.toFixed(4)}, ${longitude.toFixed(4)}`);

          if (locations.length % 5 === 0) runAiAudit(newLoc);

          if (mapRef.current) {
            const latlng = [latitude, longitude];
            mapRef.current.setView(latlng, 17);
            if (pathRef.current) pathRef.current.addLatLng(latlng);
            if (markerRef.current) {
              markerRef.current.setLatLng(latlng);
            } else {
              const pulseIcon = L.divIcon({
                className: 'custom-icon',
                html: `<div class="relative"><div class="absolute -inset-4 w-12 h-12 bg-red-500/30 rounded-full animate-ping"></div><div class="w-6 h-6 bg-[#D32F2F] rounded-full border-2 border-white shadow-xl flex items-center justify-center"></div></div>`,
                iconSize: [24, 24],
                iconAnchor: [12, 12]
              });
              markerRef.current = L.marker(latlng, { icon: pulseIcon }).addTo(mapRef.current);
            }
          }
        },
        (error) => addLog(`GPS ERROR: ${error.message}`),
        { enableHighAccuracy: true }
      );
    }

    return () => {
      clearTimeout(timer);
      if (watchIdRef.current !== null) navigator.geolocation.clearWatch(watchIdRef.current);
      if (mapRef.current) mapRef.current.remove();
    };
  }, []);

  return (
    <div className="flex flex-col h-full w-full bg-[#0F1115]">
      <div className="bg-[#D32F2F] p-5 pt-8 flex items-center justify-between shadow-2xl z-20">
        <div className="flex items-center gap-4">
          <div className="w-12 h-12 bg-white rounded-full flex items-center justify-center animate-pulse shadow-lg">
            <i className="fa-solid fa-person-running text-[#D32F2F] text-2xl"></i>
          </div>
          <div>
            <h2 className="text-white font-black uppercase text-lg tracking-widest leading-none">SOS ACTIVE</h2>
            <p className="text-white/80 text-[8px] uppercase font-black tracking-widest mt-1">Satellite Link: STABLE</p>
          </div>
        </div>
        <div className="text-right">
           <span className="text-white font-mono text-[10px] bg-black/30 px-2 py-1 rounded border border-white/10">ENC: AES-256</span>
        </div>
      </div>

      <div className="flex-1 relative">
        <div id="map-container" className="absolute inset-0 z-0 bg-gray-900"></div>

        {/* Tactical Feed Terminal */}
        <div className="absolute top-4 left-4 right-4 z-10 flex flex-col gap-2">
           <div className="bg-black/80 backdrop-blur-md border border-white/10 p-3 rounded-xl shadow-2xl">
              <div className="flex items-center gap-2 mb-2">
                 <div className="w-1.5 h-1.5 rounded-full bg-blue-500 animate-pulse"></div>
                 <span className="text-[8px] font-black text-blue-500 uppercase tracking-widest">Safety Auditor (Gemini AI)</span>
              </div>
              <p className="text-[10px] text-gray-300 font-mono italic leading-tight">{aiReport}</p>
           </div>

           <div className="bg-black/60 backdrop-blur-sm border border-white/5 p-3 rounded-xl max-h-32 overflow-hidden flex flex-col gap-1">
              {dispatchLogs.map((log, i) => (
                <p key={i} className="text-[8px] font-mono text-green-500/80 leading-tight">
                  <span className="opacity-50 mr-2">></span>{log}
                </p>
              ))}
           </div>
        </div>

        {currentCoords && (
          <div className="absolute bottom-6 left-4 right-4 z-10 bg-[#1A1D24]/95 backdrop-blur-2xl border border-white/10 rounded-[2rem] p-6 shadow-2xl">
            <div className="flex justify-between items-center mb-4">
              <span className="text-[9px] text-gray-400 font-black uppercase tracking-widest">Live Coordinate Matrix</span>
              <span className="text-[9px] text-green-500 font-black uppercase tracking-widest">Verified</span>
