import React, { useState, useEffect, useRef } from 'react';
import { EmergencyRecord, LocationUpdate, EmergencyStatus, UserProfile } from '../types';
import { firebaseService } from '../firebase';

declare const L: any;

interface TrustedContactViewProps {
  onBack: () => void;
}

const TrustedContactView: React.FC<TrustedContactViewProps> = ({ onBack }) => {
  const [activeEmergencies, setActiveEmergencies] = useState<EmergencyRecord[]>([]);
  const [selectedEmergency, setSelectedEmergency] = useState<EmergencyRecord | null>(null);
  const [victimProfile, setVictimProfile] = useState<UserProfile | null>(null);
  const [locations, setLocations] = useState<LocationUpdate[]>([]);
  const [confirmSafeId, setConfirmSafeId] = useState<string | null>(null);
  const [receiptLogs, setReceiptLogs] = useState<string[]>([]);

  const mapRef = useRef<any>(null);
  const markerRef = useRef<any>(null);
  const pathRef = useRef<any>(null);

  const addReceipt = (msg: string) => {
    const time = new Date().toLocaleTimeString();
    setReceiptLogs(prev => [`[RECV ${time}] ${msg}`, ...prev].slice(0, 10));
  };

  const refreshData = () => {
    const active = firebaseService.getAllActiveEmergencies();

    // Audit check for new emergencies
    if (active.length > activeEmergencies.length) {
      addReceipt("NEW DISTRESS SIGNAL INTERCEPTED");
    }

    setActiveEmergencies(active);

    if (active.length > 0 && !selectedEmergency) {
      handleSelectEmergency(active[0]);
    } else if (selectedEmergency) {
      const updated = active.find(e => e.emergencyId === selectedEmergency.emergencyId);
      if (updated) {
        const locs = firebaseService.getEmergencyLocations(updated.emergencyId);
        if (locs.length > locations.length) {
          addReceipt(`LATENCY: ${Date.now() - locs[locs.length-1].timestamp}ms`);
        }
        setLocations(locs);
        updateMap(locs);
      } else {
        setSelectedEmergency(null);
        setVictimProfile(null);
        addReceipt("NODE DISCONNECTED - TARGET SECURED");
      }
    }
  };

  const handleSelectEmergency = (e: EmergencyRecord) => {
    setSelectedEmergency(e);
    setVictimProfile(firebaseService.getUserById(e.userId) || null);
    const locs = firebaseService.getEmergencyLocations(e.emergencyId);
    setLocations(locs);
    updateMap(locs);
    addReceipt(`LOCK-ON ESTABLISHED: ${e.emergencyId.substr(-6)}`);
  };

  const updateMap = (locs: LocationUpdate[]) => {
    if (!mapRef.current || locs.length === 0) return;
    const latest = locs[locs.length - 1];
    const latlng = [latest.latitude, latest.longitude];
    mapRef.current.setView(latlng, 17);
    if (markerRef.current) {
      markerRef.current.setLatLng(latlng);
    } else {
      const icon = L.divIcon({
        className: 'pulse-icon',
        html: `<div class="relative"><div class="absolute -inset-6 w-16 h-16 bg-red-600/20 rounded-full animate-ping"></div><div class="w-8 h-8 bg-red-600 rounded-full border-2 border-white flex items-center justify-center shadow-2xl"><i class="fa-solid fa-person-walking-exclamation text-white text-sm"></i></div></div>`,
        iconSize: [32, 32],
        iconAnchor: [16, 16]
      });
      markerRef.current = L.marker(latlng, { icon }).addTo(mapRef.current);
    }
    if (pathRef.current) pathRef.current.setLatLngs(locs.map(l => [l.latitude, l.longitude]));
  };

  useEffect(() => {
    if (!mapRef.current) {
      mapRef.current = L.map('command-map', { zoomControl: false, attributionControl: false }).setView([20, 0], 2);
      L.tileLayer('https://{s}.basemaps.cartocdn.com/dark_all/{z}/{x}/{y}{r}.png', { maxZoom: 20 }).addTo(mapRef.current);
      pathRef.current = L.polyline([], { color: '#D32F2F', weight: 5, opacity: 0.8 }).addTo(mapRef.current);
    }
    const interval = setInterval(refreshData, 3000);
    window.addEventListener('storage_update', refreshData);
    return () => {
      clearInterval(interval);
      window.removeEventListener('storage_update', refreshData);
      if (mapRef.current) mapRef.current.remove();
    };
  }, []);

  return (
    <div className="flex flex-col h-full w-full bg-[#090B0E] text-white">
      <div className="p-6 pt-10 bg-[#12151A] border-b border-gray-800 flex items-center justify-between z-20 shadow-2xl">
        <div className="flex items-center gap-4">
          <button onClick={onBack} className="w-10 h-10 rounded-xl bg-gray-800/50 flex items-center justify-center text-gray-400">
            <i className="fa-solid fa-chevron-left"></i>
          </button>
          <div>
            <h2 className="text-xs font-black uppercase tracking-[0.3em] text-blue-500">Sentinel Hub</h2>
            <p className="text-[10px] font-bold text-gray-500 uppercase">Verification Console</p>
          </div>
        </div>
        <div className="text-right">
           <p className="text-[8px] text-gray-600 font-mono">NODE: SV-TACT-09</p>
        </div>
      </div>

      <div className="flex-1 relative">
        <div id="command-map" className="absolute inset-0 z-0 grayscale-[0.2]"></div>

        {/* Signal Receipt Audit Console */}
        <div className="absolute top-4 left-4 w-48 z-10 bg-black/80 border border-white/10 rounded-xl p-3 shadow-2xl max-h-40 overflow-hidden">
           <div className="flex items-center justify-between mb-2">
              <span className="text-[7px] font-black text-gray-500 uppercase tracking-widest">Signal Audit</span>
              <div className="w-1.5 h-1.5 rounded-full bg-green-500 animate-pulse"></div>
           </div>
           <div className="space-y-1">
              {receiptLogs.map((log, i) => (
                <p key={i} className="text-[7px] font-mono text-blue-400 leading-none truncate">{log}</p>
              ))}
           </div>
        </div>

        {selectedEmergency && victimProfile && (
          <div className="absolute bottom-6 left-4 right-4 z-10 bg-[#12151A]/95 backdrop-blur-3xl border border-white/10 rounded-[2.5rem] p-6 shadow-2xl">
            <div className="flex justify-between items-start mb-6">
              <div className="flex items-center gap-4">
                <div className="w-14 h-14 rounded-2xl bg-red-600/10 border border-red-600/30 flex items-center justify-center">
                  <i className="fa-solid fa-user-ninja text-red-500 text-2xl"></i>
                </div>
                <div>
                  <h3 className="text-white font-black text-sm uppercase">{victimProfile.name}</h3>
                  <p className="text-[9px] text-red-500 font-black uppercase tracking-widest animate-pulse">SOS ACTIVE</p>
                </div>
              </div>
              <button onClick={() => setConfirmSafeId(selectedEmergency.emergencyId)} className="bg-green-600 text-white px-5 py-2.5 rounded-xl text-[10px] font-black uppercase tracking-widest active:scale-95 transition-all">
                SECURE
              </button>
            </div>
            <div className="grid grid-cols-2 gap-4">
              <div className="bg-black/40 border border-white/5 p-4 rounded-2xl">
                <p className="text-[8px] text-gray-500 font-black uppercase mb-1">Precision</p>
                <p className="text-white font-mono text-[10px] font-bold">HIGH (3m)</p>
              </div>
              <div className="bg-black/40 border border-white/5 p-4 rounded-2xl">
                <p className="text-[8px] text-gray-500 font-black uppercase mb-1">Last Ping</p>
                <p className="text-blue-400 font-mono text-[10px] font-bold">1.2s AGO</p>
              </div>
            </div>
          </div>
        )}
      </div>

      <div className="p-6 pb-12 bg-[#12151A] border-t border-gray-800 z-20 max-h-[200px] overflow-y-auto rounded-t-[3.5rem] shadow-2xl">
        <h4 className="text-[9px] text-gray-500 font-black uppercase tracking-[0.25em] mb-4 text-center">Active Intercepts</h4>
        {activeEmergencies.length === 0 ? (
          <p className="text-[8px] text-center text-gray-600 uppercase font-black py-8 tracking-widest">All Perimeters Secure</p>
        ) : (
          <div className="space-y-3">
            {activeEmergencies.map(e => (
              <div key={e.emergencyId} onClick={() => handleSelectEmergency(e)} className={`p-4 rounded-2xl border transition-all cursor-pointer ${selectedEmergency?.emergencyId === e.emergencyId ? 'bg-red-950/20 border-red-600/50' : 'bg-gray-900 border-gray-800'}`}>
                <div className="flex justify-between items-center">
                  <span className="text-[9px] text-white font-black uppercase">NODE: {e.emergencyId.substr(-6)}</span>
                  <span className="text-[8px] text-red-500 font-black">TRACKING</span>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>

      {confirmSafeId && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-8 bg-black/80 backdrop-blur-md">
          <div className="bg-[#12151A] border border-white/10 w-full max-w-sm rounded-[3rem] p-10 text-center">
            <h3 className="text-lg font-black text-white uppercase mb-4">Secure Status?</h3>
            <p className="text-gray-500 text-[10px] font-black uppercase mb-10 leading-relaxed">Confirm target is safe to terminate live tracking broadcast.</p>
            <div className="flex flex-col gap-3">
              {/* Fix: Replaced logical OR in onClick with a block for safe sequential void function execution */}
              <button 
                onClick={() => {
                  if (confirmSafeId) {
                    firebaseService.resolveEmergency(confirmSafeId);
                    setConfirmSafeId(null);
                  }
                }} 
                className="w-full bg-green-600 text-white font-black py-5 rounded-2xl uppercase tracking-widest"
              >
                Confirm Safe
              </button>
              <button onClick={() => setConfirmSafeId(null)} className="w-full text-gray-600 font-black py-2 uppercase text-[9px]">Cancel</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default TrustedContactView;

import React, { useState, useEffect, useRef } from 'react';
import { UserProfile, Contact } from '../types';
import { firebaseService } from '../firebase';

interface SettingsScreenProps {
  user: UserProfile;
  onBack: () => void;
  refreshUser: () => void;
}

const SettingsScreen: React.FC<SettingsScreenProps> = ({ user, onBack, refreshUser }) => {
  const [keyword, setKeyword] = useState(user.emergencyKeyword);
  const [contacts, setContacts] = useState<Contact[]>([]);
  const [newContact, setNewContact] = useState({ name: '', phone: '' });
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    setContacts(firebaseService.getContacts(user.userId));
  }, [user.userId]);

  const saveKeyword = () => {
    firebaseService.updateProfile(user.userId, { emergencyKeyword: keyword.toUpperCase() });
    refreshUser();
    alert("Voice Protocol Cipher Updated.");
  };

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        const base64String = reader.result as string;
        firebaseService.updateProfile(user.userId, { profilePic: base64String });
        refreshUser();
      };
      reader.readAsDataURL(file);
    }
  };

  const addContact = () => {
    if (!newContact.name || !newContact.phone) return;
    const contact: Contact = {
      contactId: 'c_' + Date.now(),
      userId: user.userId,
      name: newContact.name,
      phone: newContact.phone,
      relationship: 'Trusted'
    };
    firebaseService.addContact(contact);
    setContacts([...contacts, contact]);
    setNewContact({ name: '', phone: '' });
  };

  const deleteContact = (id: string) => {
    firebaseService.deleteContact(id);
    setContacts(contacts.filter(c => c.contactId !== id));
  };

  const userInitials = user.name.split(' ').map(n => n[0]).join('').toUpperCase().slice(0, 2);

  return (
    <div className="flex flex-col h-full w-full bg-[#0F1115]">
      <div className="p-6 pt-10 flex items-center gap-4 bg-[#1A1D24] border-b border-gray-800">
        <button onClick={onBack} className="w-10 h-10 rounded-xl bg-gray-800 flex items-center justify-center text-gray-400 hover:text-white transition-all">
          <i className="fa-solid fa-arrow-left"></i>
        </button>
        <h2 className="text-sm font-black text-white uppercase tracking-[0.25em]">Config Terminal</h2>
      </div>

      <div className="flex-1 overflow-y-auto p-6 space-y-8 pb-10">
        {/* Profile Identity Section */}
        <section>
          <div className="flex justify-between items-center mb-4">
             <h3 className="text-[10px] text-gray-500 uppercase font-black tracking-widest">Biometric Identity</h3>
             <i className="fa-solid fa-fingerprint text-green-500 text-xs"></i>
          </div>
          <div className="bg-[#1A1D24] p-6 rounded-3xl border border-gray-800 shadow-xl flex flex-col items-center">
             <div 
               onClick={() => fileInputRef.current?.click()}
               className="relative w-24 h-24 rounded-[2rem] bg-gray-800 border-2 border-dashed border-gray-700 flex items-center justify-center cursor-pointer hover:border-[#D32F2F] transition-all overflow-hidden group"
             >
                {user.profilePic ? (
                  <img src={user.profilePic} alt="Profile" className="w-full h-full object-cover group-hover:opacity-40 transition-opacity" />
                ) : (
                  <span className="text-gray-500 font-black text-xl group-hover:opacity-20 transition-opacity">{userInitials}</span>
                )}
                <div className="absolute inset-0 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity bg-[#D32F2F]/20">
                   <i className="fa-solid fa-camera text-white"></i>
                </div>
                <input 
                  type="file" 
                  ref={fileInputRef} 
                  className="hidden" 
                  accept="image/*" 
                  onChange={handleImageUpload}
                />
             </div>

             <div className="w-full mt-6 space-y-3">
                <div className="bg-black/30 p-4 rounded-2xl border border-white/5">
                   <p className="text-[8px] text-gray-500 font-black uppercase mb-1">Authenticated Operative</p>
                   <p className="text-white text-xs font-bold">{user.name}</p>
                </div>
                <div className="bg-black/30 p-4 rounded-2xl border border-white/5">
                   <p className="text-[8px] text-gray-500 font-black uppercase mb-1">Verified Comms</p>
                   <p className="text-white text-xs font-mono">{user.phone}</p>
                </div>
             </div>
          </div>
        </section>

        {/* Keyword Setting */}
        <section>
          <div className="flex justify-between items-center mb-4">
             <h3 className="text-[10px] text-gray-500 uppercase font-black tracking-widest">Voice Protocol</h3>
             <i className="fa-solid fa-microphone text-red-500 text-xs animate-pulse"></i>
          </div>
          <div className="bg-[#1A1D24] p-5 rounded-3xl border border-gray-800 shadow-xl">
            <p className="text-[10px] text-gray-500 mb-4 leading-relaxed font-black uppercase tracking-tighter">Emergency Cipher:</p>
            <div className="flex gap-2">
              <input 
                value={keyword}
                onChange={(e) => setKeyword(e.target.value.toUpperCase())}
                className="flex-1 bg-black/40 border border-gray-700 rounded-2xl p-4 text-white font-mono tracking-[0.3em] text-lg focus:outline-none focus:border-[#D32F2F]"
                placeholder="CIPHER"
              />
              <button 
                onClick={saveKeyword}
                className="bg-[#D32F2F] text-white px-6 rounded-2xl font-black text-[10px] uppercase tracking-widest shadow-lg shadow-red-900/20 active:scale-95 transition-all"
              >
                Sync
              </button>
            </div>
          </div>
        </section>

        {/* Contacts Section */}
        <section>
          <div className="flex justify-between items-center mb-4">
             <h3 className="text-[10px] text-gray-500 uppercase font-black tracking-widest">Response Network ({contacts.length}/5)</h3>
             <i className="fa-solid fa-users-viewfinder text-blue-500 text-xs"></i>
          </div>

          <div className="space-y-3 mb-6">
            {contacts.map(contact => (
              <div key={contact.contactId} className="bg-[#1A1D24] p-5 rounded-3xl border border-gray-800 flex justify-between items-center group">
                <div className="flex items-center gap-4">
                  <div className="w-11 h-11 rounded-2xl bg-gray-800 flex items-center justify-center border border-white/5">
                    <i className="fa-solid fa-user-shield text-[#D32F2F] text-sm"></i>
                  </div>
                  <div>
                    <h4 className="text-xs font-black text-white uppercase tracking-tight">{contact.name}</h4>
                    <p className="text-[10px] text-gray-600 font-mono mt-1">{contact.phone}</p>
                  </div>
                </div>
                <button onClick={() => deleteContact(contact.contactId)} className="w-8 h-8 rounded-lg bg-red-500/10 text-red-500/50 hover:text-red-500 transition-colors">
                  <i className="fa-solid fa-trash-can text-xs"></i>
                </button>
              </div>
            ))}
          </div>

          <div className="bg-[#1A1D24] p-6 rounded-[2.5rem] border border-gray-800 shadow-2xl">
             <p className="text-[10px] text-gray-500 uppercase font-black tracking-widest mb-4">Initialize New Tie</p>
             <div className="space-y-3">
                <input 
                  placeholder="Operative Name (e.g. John)"
                  value={newContact.name}
                  onChange={(e) => setNewContact({...newContact, name: e.target.value})}
                  className="w-full bg-black/40 border border-gray-700 rounded-2xl p-4 text-white text-xs font-bold placeholder:text-gray-700 focus:outline-none"
                />
                <input 
                  placeholder="Comms Number (e.g. +1 555-0101)"
                  value={newContact.phone}
                  onChange={(e) => setNewContact({...newContact, phone: e.target.value})}
                  className="w-full bg-black/40 border border-gray-700 rounded-2xl p-4 text-white text-xs font-mono placeholder:text-gray-700 focus:outline-none"
                />
                <button 
                  onClick={addContact}
                  className="w-full bg-[#D32F2F] text-white font-black py-4 rounded-2xl text-[10px] uppercase tracking-[0.2em] shadow-lg active:scale-95 transition-all mt-2"
                >
                  Verify and Add
                </button>
             </div>
             <p className="mt-4 text-[8px] text-gray-600 font-black uppercase text-center leading-relaxed">
               Note: Enter any phone number. In this prototype, <br/>alerts are sent via shared browser state.
             </p>
          </div>
        </section>
      </div>
    </div>
  );
};

