import React, { useState, useEffect, useRef } from 'react';
import { UserProfile, EmergencyRecord, LocationUpdate } from '../types';
import { firebaseService } from '../firebase';
import { GoogleGenAI } from "@google/genai";

declare const L: any;

interface EmergencyScreenProps {
  user: UserProfile;
  emergency: EmergencyRecord;
  onResolve: () => void;
}

const EmergencyScreen: React.FC<EmergencyScreenProps> = ({ user, emergency, onResolve }) => {
  const [locations, setLocations] = useState<LocationUpdate[]>([]);
  const [currentCoords, setCurrentCoords] = useState<{lat: number, lng: number} | null>(null);
  const [dispatchLogs, setDispatchLogs] = useState<string[]>([]);
  const [aiReport, setAiReport] = useState<string>("Initializing Safety Audit...");

  const mapRef = useRef<any>(null);
  const markerRef = useRef<any>(null);
  const pathRef = useRef<any>(null);
  const watchIdRef = useRef<number | null>(null);

  const addLog = (msg: string) => {
    const time = new Date().toLocaleTimeString([], { hour12: false });
    setDispatchLogs(prev => [`[${time}] ${msg}`, ...prev].slice(0, 6));
  };

  const runAiAudit = async (loc: LocationUpdate) => {
    try {
      if (!process.env.API_KEY || process.env.API_KEY === '') {
         setAiReport("[AUDIT OFFLINE] System utilizing local coordinate verification only.");
         return;
      }
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `PRO DISPATCHER MODE: Analyze the following safety metadata and produce a 10-word tactical status verification.
        Subject: ${user.name}
        Coords: ${loc.latitude}, ${loc.longitude}
        SOS Priority: CRITICAL
        Context: Real-time distress signal active.`
      });
      setAiReport(response.text?.trim() || "Coordinates verified by AI core. Response initiated.");
    } catch (e) {
      console.warn("AI Audit Error:", e);
      setAiReport("Audit Link Active. Tracking Node " + emergency.emergencyId.slice(-4));
    }
  };

  useEffect(() => {
    addLog("CRITICAL: SOS BROADCAST STARTED");
    const contacts = firebaseService.getContacts(user.userId);
    contacts.forEach(c => addLog(`NOTIFIED: ${c.name.toUpperCase()}`));

    const initMap = () => {
      const container = document.getElementById('map-container');
      if (container && !mapRef.current) {
        mapRef.current = L.map('map-container', {
          zoomControl: false,
          attributionControl: false
        }).setView([0, 0], 2);

        L.tileLayer('https://{s}.basemaps.cartocdn.com/dark_all/{z}/{x}/{y}{r}.png', { maxZoom: 19 }).addTo(mapRef.current);
        pathRef.current = L.polyline([], { color: '#D32F2F', weight: 4, opacity: 0.8 }).addTo(mapRef.current);
      }
    };

    const timer = setTimeout(initMap, 200);

    if ("geolocation" in navigator) {
      watchIdRef.current = navigator.geolocation.watchPosition(
        (position) => {
          const { latitude, longitude } = position.coords;
          const newLoc = { emergencyId: emergency.emergencyId, latitude, longitude, timestamp: Date.now() };

          firebaseService.pushLocation(newLoc);
          setCurrentCoords({ lat: latitude, lng: longitude });

          setLocations(prev => {
            const next = [...prev, newLoc];
            // Audit every 5 updates for performance and token saving
            if (next.length === 1 || next.length % 5 === 0) {
              runAiAudit(newLoc);
            }
            return next;
          });

          addLog(`TX PKT: ${latitude.toFixed(4)}, ${longitude.toFixed(4)}`);

          if (mapRef.current) {
            const latlng = [latitude, longitude];
            mapRef.current.setView(latlng, 17);
            if (pathRef.current) pathRef.current.addLatLng(latlng);
            if (markerRef.current) {
              markerRef.current.setLatLng(latlng);
            } else {
              const pulseIcon = L.divIcon({
                className: 'custom-icon',
                html: `<div class="relative">
                  <div class="absolute -inset-6 w-16 h-16 bg-red-600/20 rounded-full animate-ping"></div>
                  <div class="w-8 h-8 bg-[#D32F2F] rounded-full border-2 border-white shadow-[0_0_15px_rgba(211,47,47,1)] flex items-center justify-center">
                    <div class="w-2 h-2 bg-white rounded-full animate-pulse"></div>
                  </div>
                </div>`,
                iconSize: [32, 32],
                iconAnchor: [16, 16]
              });
              markerRef.current = L.marker(latlng, { icon: pulseIcon }).addTo(mapRef.current);
            }
          }
        },
        (error) => addLog(`SENSOR ERROR: ${error.message}`),
        { enableHighAccuracy: true, timeout: 5000, maximumAge: 0 }
      );
    }

    return () => {
      clearTimeout(timer);
      if (watchIdRef.current !== null) navigator.geolocation.clearWatch(watchIdRef.current);
      if (mapRef.current) mapRef.current.remove();
    };
  }, [emergency.emergencyId, user.name, user.userId]);

