import React, { useState, useEffect, useRef } from 'react';
import { UserProfile, EmergencyRecord, LocationUpdate } from '../types';
import { firebaseService } from '../firebase';
import { GoogleGenAI } from "@google/genai";

declare const L: any;

interface EmergencyScreenProps {
  user: UserProfile;
  emergency: EmergencyRecord;
  onResolve: () => void;
}

const EmergencyScreen: React.FC<EmergencyScreenProps> = ({ user, emergency, onResolve }) => {
  const [locations, setLocations] = useState<LocationUpdate[]>([]);
  const [currentCoords, setCurrentCoords] = useState<{lat: number, lng: number} | null>(null);
  const [dispatchLogs, setDispatchLogs] = useState<string[]>([]);
  const [aiReport, setAiReport] = useState<string>("Verifying Signal...");

  const mapRef = useRef<any>(null);
  const markerRef = useRef<any>(null);
  const pathRef = useRef<any>(null);
  const watchIdRef = useRef<number | null>(null);

  const addLog = (msg: string) => {
    const time = new Date().toLocaleTimeString([], { hour12: false, hour: '2-digit', minute: '2-digit' });
    setDispatchLogs(prev => [`${time} > ${msg}`, ...prev].slice(0, 4));
  };

  const runAiAudit = async (loc: LocationUpdate) => {
    try {
      if (!process.env.API_KEY || process.env.API_KEY === '') return;
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Status brief (5 words max) for SOS at ${loc.latitude}, ${loc.longitude}. Focus: Tactical stability.`
      });
      setAiReport(response.text?.trim() || "Active Tracking");
    } catch (e) {
      setAiReport("Audit Node Active");
    }
  };

  useEffect(() => {
    addLog("SOS BROADCAST INITIATED");
    const initMap = () => {
      const container = document.getElementById('map-container');
      if (container && !mapRef.current) {
        mapRef.current = L.map('map-container', {
          zoomControl: false,
          attributionControl: false
        }).setView([0, 0], 2);
        L.tileLayer('https://{s}.basemaps.cartocdn.com/dark_all/{z}/{x}/{y}{r}.png').addTo(mapRef.current);
        pathRef.current = L.polyline([], { color: '#D32F2F', weight: 4, opacity: 0.6 }).addTo(mapRef.current);
      }
    };

    setTimeout(initMap, 100);

    if ("geolocation" in navigator) {
      watchIdRef.current = navigator.geolocation.watchPosition(
        (position) => {
          const { latitude, longitude } = position.coords;
          const newLoc = { emergencyId: emergency.emergencyId, latitude, longitude, timestamp: Date.now() };
          firebaseService.pushLocation(newLoc);
          setCurrentCoords({ lat: latitude, lng: longitude });
          setLocations(prev => {
            const next = [...prev, newLoc];
            if (next.length === 1 || next.length % 8 === 0) runAiAudit(newLoc);
            return next;
          });
          if (mapRef.current) {
            const latlng = [latitude, longitude];
            mapRef.current.setView(latlng, 17);
            if (pathRef.current) pathRef.current.addLatLng(latlng);
            if (!markerRef.current) {
              const icon = L.divIcon({
                className: 'm-0',
                html: `<div class="w-6 h-6 bg-[#D32F2F] rounded-full border-2 border-white shadow-[0_0_20px_#D32F2F] animate-pulse"></div>`,
                iconSize: [24, 24],
                iconAnchor: [12, 12]
              });
              markerRef.current = L.marker(latlng, { icon }).addTo(mapRef.current);
            } else {
              markerRef.current.setLatLng(latlng);
            }
          }
        },
        null,
        { enableHighAccuracy: true }
      );
    }
    return () => {
      if (watchIdRef.current !== null) navigator.geolocation.clearWatch(watchIdRef.current);
      if (mapRef.current) mapRef.current.remove();
    };
  }, [emergency.emergencyId]);

  return (
    <div className="relative h-full w-full bg-[#0F1115] overflow-hidden">
      {/* Background Map - Zero Occlusion */}
      <div id="map-container" className="absolute inset-0 z-0"></div>

      {/* Top Floating HUD */}
      <div className="absolute top-10 left-4 right-4 z-10 flex flex-col gap-2 pointer-events-none">
        <div className="flex justify-between items-center bg-black/40 backdrop-blur-md border border-white/10 rounded-2xl p-3 pointer-events-auto">
          <div className="flex items-center gap-3">
             <div className="w-8 h-8 bg-red-600 rounded-lg flex items-center justify-center shadow-lg animate-pulse">
                <i className="fa-solid fa-satellite-dish text-white text-xs"></i>
             </div>
             <div>
               <h2 className="text-white font-black text-[10px] uppercase tracking-widest">SOS ACTIVE</h2>
               <p className="text-white/50 text-[7px] font-mono">ID: {emergency.emergencyId.slice(-6)}</p>
             </div>
          </div>
          <div className="text-right">
             <p className="text-blue-400 font-black text-[8px] uppercase tracking-tighter italic">{aiReport}</p>
             <p className="text-emerald-500 font-mono text-[7px] mt-0.5">STREAMING LIVE</p>
          </div>
        </div>

        {/* Floating Mini Logs */}
        <div className="w-3/4 bg-black/30 backdrop-blur-sm border-l-2 border-red-500/50 p-2 rounded-r-xl">
           {dispatchLogs.map((log, i) => (
             <p key={i} className="text-[7px] font-mono text-white/60 leading-tight mb-0.5 truncate">{log}</p>
           ))}
        </div>
      </div>

      {/* Bottom Docked Controls */}
      <div className="absolute bottom-8 left-6 right-6 z-10 space-y-4">
        {currentCoords && (
          <div className="flex justify-center">
            <div className="bg-black/60 backdrop-blur-xl border border-white/5 px-4 py-2 rounded-full flex gap-4 shadow-2xl">
              <div className="flex items-center gap-2">
                <span className="text-[7px] text-gray-500 font-black uppercase">LAT</span>
                <span className="text-white font-mono text-[9px]">{currentCoords.lat.toFixed(5)}</span>
              </div>
              <div className="w-px h-3 bg-white/10 my-auto"></div>
              <div className="flex items-center gap-2">
                <span className="text-[7px] text-gray-500 font-black uppercase">LNG</span>
                <span className="text-white font-mono text-[9px]">{currentCoords.lng.toFixed(5)}</span>
              </div>
            </div>
          </div>
        )}

        <button 
          onClick={onResolve}
          className="w-full bg-[#10B981] hover:bg-emerald-400 text-white py-5 rounded-3xl font-black text-sm tracking-[0.3em] shadow-[0_15px_40px_rgba(16,185,129,0.3)] active:scale-95 transition-all uppercase"
        >
          Mark as Safe
        </button>
      </div>
    </div>
  );
};

export default EmergencyScreen;

import React, { useState, useEffect, useRef } from 'react';
import { EmergencyRecord, LocationUpdate, UserProfile } from '../types';
import { firebaseService } from '../firebase';

declare const L: any;

interface TrustedContactViewProps {
  onBack: () => void;
}

const TrustedContactView: React.FC<TrustedContactViewProps> = ({ onBack }) => {
  const [activeEmergencies, setActiveEmergencies] = useState<EmergencyRecord[]>([]);
  const [selectedEmergency, setSelectedEmergency] = useState<EmergencyRecord | null>(null);
  const [victimProfile, setVictimProfile] = useState<UserProfile | null>(null);
  const [confirmSafeId, setConfirmSafeId] = useState<string | null>(null);

  const mapRef = useRef<any>(null);
  const markerRef = useRef<any>(null);
  const pathRef = useRef<any>(null);

  const refreshData = () => {
    const active = firebaseService.getAllActiveEmergencies();
    setActiveEmergencies(active);

    if (selectedEmergency) {
      const stillActive = active.find(e => e.emergencyId === selectedEmergency.emergencyId);
      if (stillActive) {
        const locs = firebaseService.getEmergencyLocations(stillActive.emergencyId);
        updateMap(locs);
      } else {
        setSelectedEmergency(null);
        setVictimProfile(null);
      }
    }
  };

  const updateMap = (locs: LocationUpdate[]) => {
    if (!mapRef.current || locs.length === 0) return;
    const latest = locs[locs.length - 1];
    const latlng = [latest.latitude, latest.longitude];
    mapRef.current.setView(latlng, 17);
    if (markerRef.current) {
      markerRef.current.setLatLng(latlng);
    } else {
      const icon = L.divIcon({
        className: 'm-0',
        html: `<div class="w-8 h-8 bg-red-600 rounded-full border-2 border-white flex items-center justify-center shadow-2xl animate-pulse"><i class="fa-solid fa-person-walking-exclamation text-white text-xs"></i></div>`,
        iconSize: [32, 32],
        iconAnchor: [16, 16]
      });
      markerRef.current = L.marker(latlng, { icon }).addTo(mapRef.current);
    }
    if (pathRef.current) pathRef.current.setLatLngs(locs.map(l => [l.latitude, l.longitude]));
  };

  useEffect(() => {
    if (!mapRef.current) {
      mapRef.current = L.map('command-map', { zoomControl: false, attributionControl: false }).setView([20, 0], 2);
      L.tileLayer('https://{s}.basemaps.cartocdn.com/dark_all/{z}/{x}/{y}{r}.png').addTo(mapRef.current);
      pathRef.current = L.polyline([], { color: '#D32F2F', weight: 4, opacity: 0.5 }).addTo(mapRef.current);
    }
    const interval = setInterval(refreshData, 3000);
    return () => {
      clearInterval(interval);
      if (mapRef.current) mapRef.current.remove();
    };
  }, []);

  const selectEmergency = (e: EmergencyRecord) => {
    setSelectedEmergency(e);
    setVictimProfile(firebaseService.getUserById(e.userId) || null);
    const locs = firebaseService.getEmergencyLocations(e.emergencyId);
    updateMap(locs);
  };

  return (
    <div className="relative h-full w-full bg-[#090B0E] text-white overflow-hidden">
      {/* Immersive Map Background */}
      <div id="command-map" className="absolute inset-0 z-0 grayscale-[0.3]"></div>

      {/* HUD Header */}
      <div className="absolute top-10 left-4 right-4 z-10 flex items-center justify-between">
        <button onClick={onBack} className="w-12 h-12 rounded-2xl bg-black/40 backdrop-blur-md border border-white/10 flex items-center justify-center text-white active:scale-90 transition-all">
          <i className="fa-solid fa-chevron-left"></i>
        </button>
        <div className="bg-black/40 backdrop-blur-md border border-white/10 rounded-2xl px-5 py-2 flex flex-col items-center">
          <span className="text-[8px] font-black tracking-[0.4em] text-blue-500 uppercase">Sentinel Command</span>
          <span className="text-[6px] text-emerald-500 font-mono">LINK STABLE // HUB-01</span>
        </div>
        <div className="w-12 h-12 rounded-2xl bg-black/40 backdrop-blur-md border border-white/10 flex items-center justify-center text-emerald-500">
           <i className="fa-solid fa-tower-broadcast animate-pulse"></i>
        </div>
      </div>

      {/* Floating Target View */}
      {selectedEmergency && victimProfile && (
        <div className="absolute bottom-40 left-6 right-6 z-10 pointer-events-none">
          <div className="bg-black/60 backdrop-blur-2xl border border-white/10 rounded-3xl p-4 shadow-2xl pointer-events-auto">
             <div className="flex items-center gap-3">
                <div className="w-10 h-10 rounded-xl bg-red-600/20 border border-red-600/50 flex items-center justify-center">
                   <i className="fa-solid fa-crosshairs text-red-500"></i>
                </div>
                <div className="flex-1">
                   <h3 className="text-[11px] font-black uppercase text-white tracking-tight">{victimProfile.name}</h3>
                   <p className="text-[7px] font-mono text-red-500 uppercase">Distress Signal Active</p>
                </div>
                <button 
                  onClick={() => setConfirmSafeId(selectedEmergency.emergencyId)}
                  className="bg-emerald-600 px-3 py-2 rounded-xl text-[8px] font-black uppercase tracking-widest active:scale-90 transition-all"
                >
                  Mark Safe
                </button>
             </div>
          </div>
        </div>
      )}

      {/* Collapsible Intercept List (Docked Bottom) */}
      <div className="absolute bottom-0 left-0 right-0 z-20 bg-gradient-to-t from-black to-transparent pt-10 pb-8 px-6">
        <div className="bg-black/40 backdrop-blur-lg border-t border-white/10 rounded-t-[2.5rem] p-5 max-h-[140px] overflow-y-auto">
           <p className="text-[7px] text-gray-500 font-black uppercase tracking-widest mb-3 text-center">Active Signal Intercepts</p>
           {activeEmergencies.length === 0 ? (
             <p className="text-center text-[8px] text-gray-700 py-4 italic font-mono uppercase">Scanning Perimeter...</p>
           ) : (
             <div className="flex flex-col gap-2">
               {activeEmergencies.map(e => (
                 <div 
                   key={e.emergencyId} 
                   onClick={() => selectEmergency(e)}
                   className={`px-4 py-3 rounded-2xl border transition-all flex justify-between items-center ${selectedEmergency?.emergencyId === e.emergencyId ? 'bg-red-500/20 border-red-500' : 'bg-white/5 border-white/10'}`}
                 >
                   <span className="text-[9px] font-black text-white">TARGET: {e.emergencyId.slice(-6)}</span>
                   <div className="w-2 h-2 rounded-full bg-red-500 animate-ping"></div>
                 </div>
               ))}
