import twilio from "twilio";

const client = twilio(
  process.env.TWILIO_ACCOUNT_SID,
  process.env.TWILIO_AUTH_TOKEN
);

export default async function handler(req, res) {
  if (req.method !== "POST") {
    return res.status(405).json({ error: "Method not allowed" });
  }

  try {
    const { userName, emergencyId, contacts } = req.body;

    if (!userName || !emergencyId || !contacts?.length) {
      return res.status(400).json({ error: "Invalid payload" });
    }

    const trackingLink = `${process.env.APP_URL}/track/${emergencyId}`;

    const messageBody = `
🚨 EMERGENCY ALERT
${userName} needs help.

Live location:
${trackingLink}
`;

    const results = [];

    for (const contact of contacts) {
      try {
        const msg = await client.messages.create({
          body: messageBody,
          from: process.env.TWILIO_SMS_FROM,
          to: contact.phone,
        });

        results.push({ phone: contact.phone, status: "sent", sid: msg.sid });
      } catch (err) {
        results.push({ phone: contact.phone, status: "failed" });
      }
    }

    return res.status(200).json({
      success: true,
      results,
    });
  } catch (error) {
    console.error("SMS ERROR:", error);
    return res.status(500).json({ error: "Failed to send SMS alerts" });
  }
}


