4️⃣ The actual tracking page (THIS IS THE GOLD)

📁 pages/track/[id].js

import { useEffect, useState } from "react";
import { useRouter } from "next/router";
import { doc, onSnapshot } from "firebase/firestore";
import { db } from "../../lib/firebase";
import { GoogleMap, Marker, useLoadScript } from "@react-google-maps/api";

const mapContainerStyle = {
  width: "100%",
  height: "100vh",
};

export default function TrackEmergency() {
  const router = useRouter();
  const { id } = router.query;

  const [location, setLocation] = useState(null);

  const { isLoaded } = useLoadScript({
    googleMapsApiKey: process.env.NEXT_PUBLIC_GOOGLE_MAPS_API_KEY,
  });

  useEffect(() => {
    if (!id) return;

    const locationRef = doc(db, "locations", id);

    const unsubscribe = onSnapshot(locationRef, (snapshot) => {
      if (snapshot.exists()) {
        setLocation(snapshot.data());
      }
    });

    return () => unsubscribe();
  }, [id]);

  if (!isLoaded) {
    return <p style={{ textAlign: "center" }}>Loading map…</p>;
  }

  if (!location) {
    return <p style={{ textAlign: "center" }}>Waiting for location…</p>;
  }

  return (
    <GoogleMap
      mapContainerStyle={mapContainerStyle}
      zoom={16}
      center={{ lat: location.lat, lng: location.lng }}
    >
      <Marker position={{ lat: location.lat, lng: location.lng }} />
    </GoogleMap>
  );
}

5️⃣ What makes this live

onSnapshot() listens to Firestore in real time

Every GPS update → marker moves instantly

No refresh needed

Works on judge’s phone browser

This is real live tracking, not polling, not fake.

6️⃣ URL structure (important)

When SMS is sent, link should be:

https://your-app.vercel.app/track/<emergencyId>


Example:

https://safe-voice.vercel.app/track/abc123


Judges click → map opens → marker moves → jaws drop.

7️⃣ Common mistakes (DON’T DO THESE)

❌ Using Google Maps iframe (not live)
❌ Polling with setInterval
❌ Asking login to view tracking
❌ Hardcoding coordinates
❌ Not restricting Maps 
