      return;
    }
    setTestLoading(true);
    try {
      const result = await firebaseService.broadcastAlerts(user.name, "TEST_SIGNAL", contacts);
      if (result.simulated) {
        alert("TEST COMPLETE: Twilio credentials missing in Vercel. Signal logged to console only.");
