import twilio from "twilio";

const twilioSid = process.env.TWILIO_ACCOUNT_SID;
const twilioToken = process.env.TWILIO_AUTH_TOKEN;
const twilioFrom = process.env.TWILIO_SMS_FROM;
const appUrl = process.env.APP_URL || 'https://safe-voice.vercel.app';

// Initialize client only if keys are present
const client = twilioSid && twilioToken ? twilio(twilioSid, twilioToken) : null;

export default async function handler(req: any, res: any) {
  if (req.method !== "POST") {
    return res.status(405).json({ error: "Method not allowed" });
  }

  try {
    const { userName, emergencyId, contacts } = req.body;

    if (!userName || !emergencyId || !contacts?.length) {
      return res.status(400).json({ error: "Invalid payload: missing parameters." });
    }

    if (!client) {
      console.warn("[Twilio Backend] Credentials missing in environment variables.");
      return res.status(200).json({ 
        success: false, 
        simulated: true, 
        error: "Backend Config Error: Missing keys in Vercel settings.",
        message: "SMS sequence logged to console instead of Twilio." 
      });
    }

    const trackingLink = `${appUrl}/track?id=${emergencyId}`;
    const messageBody = emergencyId === "TEST_SIGNAL" 
      ? `🚨 SAFE-VOICE TEST SIGNAL\nUplink verified for ${userName}.\nNo response needed.`
      : `🚨 EMERGENCY ALERT\n${userName} needs help.\n\nLive tracking:\n${trackingLink}`;

    const results = [];
    let sentCount = 0;

    for (const contact of contacts) {
      try {
        // Simple E.164 check: must start with +
        const targetPhone = contact.phone.startsWith('+') ? contact.phone : `+${contact.phone}`;

        const msg = await client.messages.create({
          body: messageBody,
          from: twilioFrom,
          to: targetPhone,
        });

        results.push({ phone: targetPhone, status: "sent", sid: msg.sid });
        sentCount++;
      } catch (err: any) {
        console.error(`[Twilio Error] Failed to alert ${contact.phone}:`, err.message);
        results.push({ phone: contact.phone, status: "failed", error: err.message });
      }
    }

    return res.status(200).json({
      success: sentCount > 0,
      sentCount,
      results,
    });
  } catch (error: any) {
    console.error("[Twilio Critical Error]:", error);
    return res.status(500).json({ success: false, error: error.message || "Internal Server Error" });
  }
}

