    saveDB(db);
    localStorage.setItem('SAFE_VOICE_SESSION', JSON.stringify(user));
    return user;
  },

  login: async (email: string): Promise<UserProfile> => {
    const db = getDB();
    const user = db.users[email.toLowerCase()] as UserProfile;
    if (!user) throw new Error("Access Denied.");
    localStorage.setItem('SAFE_VOICE_SESSION', JSON.stringify(user));
    return user;
  },

  logout: () => localStorage.removeItem('SAFE_VOICE_SESSION'),

  updateProfile: (userId: string, updates: Partial<UserProfile>) => {
    const db = getDB();
    const emailKey = Object.keys(db.users).find(key => db.users[key].userId === userId);
    if (emailKey) {
      db.users[emailKey] = { ...db.users[emailKey], ...updates };
      saveDB(db);
      localStorage.setItem('SAFE_VOICE_SESSION', JSON.stringify(db.users[emailKey]));
    }
  },

  getContacts: (userId: string): Contact[] => {
    return getDB().contacts.filter((c: Contact) => c.userId === userId);
  },

  addContact: (contact: Contact) => {
    const db = getDB();
    db.contacts.push(contact);
    saveDB(db);
  },

  deleteContact: (contactId: string) => {
    const db = getDB();
    db.contacts = db.contacts.filter((c: Contact) => c.contactId !== contactId);
    saveDB(db);
  },

  triggerEmergency: (userId: string): string => {
    const db = getDB();
    const emergencyId = 'e_' + Date.now();
    const record: EmergencyRecord = { emergencyId, userId, status: EmergencyStatus.ACTIVE, triggeredAt: Date.now() };
    db.emergencies.push(record);
    saveDB(db);

    const user = Object.values(db.users).find((u: any) => u.userId === userId) as UserProfile;
    const contacts = db.contacts.filter((c: Contact) => c.userId === userId);

    if (user) {
      // Trigger background alert sequence
      firebaseService.broadcastAlerts(user.name, emergencyId, contacts);
    }

    return emergencyId;
  },

  broadcastAlerts: async (userName: string, emergencyId: string, contacts: Contact[]) => {
    console.log(`[Twilio Dispatch] Targeting ${contacts.length} responders...`);
    try {
      const response = await fetch('/api/send-sms-alert', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ userName, emergencyId, contacts })
      });
      const data = await response.json();

      // Dispatch custom event for UI feedback on dispatch status
      window.dispatchEvent(new CustomEvent('twilio_dispatch_result', { detail: data }));
      return data;
    } catch (err) {
      console.error("[Twilio Dispatch] Network failure:", err);
      const errorData = { success: false, error: 'Network Connection Failed' };
      window.dispatchEvent(new CustomEvent('twilio_dispatch_result', { detail: errorData }));
      return errorData;
    }
  },

  resolveEmergency: (emergencyId: string) => {
    const db = getDB();
    const record = db.emergencies.find((e: EmergencyRecord) => e.emergencyId === emergencyId);
    if (record) {
      record.status = EmergencyStatus.SAFE;
      record.resolvedAt = Date.now();
      saveDB(db);
    }
  },

  getAllActiveEmergencies: (): EmergencyRecord[] => {
    return getDB().emergencies.filter((e: EmergencyRecord) => e.status === EmergencyStatus.ACTIVE);
  },

  getActiveEmergency: (userId: string): EmergencyRecord | undefined => {
    return getDB().emergencies.find((e: EmergencyRecord) => e.userId === userId && e.status === EmergencyStatus.ACTIVE);
  },

  getUserById: (userId: string): UserProfile | undefined => {
    const db = getDB();
    return Object.values(db.users).find((u: any) => u.userId === userId) as UserProfile;
  },

  pushLocation: (location: LocationUpdate) => {
    const db = getDB();
    db.locations.push(location);
    saveDB(db);
  },

  getEmergencyLocations: (emergencyId: string): LocationUpdate[] => {
    return getDB().locations.filter((l: LocationUpdate) => l.emergencyId === emergencyId);
  }
};

import twilio from "twilio";

const twilioSid = process.env.TWILIO_ACCOUNT_SID;
const twilioToken = process.env.TWILIO_AUTH_TOKEN;
const twilioFrom = process.env.TWILIO_SMS_FROM;
const appUrl = process.env.APP_URL || 'https://safe-voice.vercel.app';

export default async function handler(req: any, res: any) {
  // Only allow POST requests
  if (req.method !== "POST") {
    return res.status(405).json({ error: "Method not allowed" });
  }

  try {
    const { userName, emergencyId, contacts } = req.body;

    if (!userName || !emergencyId || !contacts?.length) {
      return res.status(400).json({ error: "Payload parameters missing." });
    }

    // Check for missing credentials in the environment
    if (!twilioSid || !twilioToken || !twilioFrom) {
      console.error("[Twilio Config] Missing SID, Token, or From number in Vercel.");
      return res.status(200).json({ 
        success: false, 
        error: "Server configuration missing (Twilio keys).",
        details: "Vercel environment variables are not set."
      });
    }

    const client = twilio(twilioSid, twilioToken);
    const trackingLink = `${appUrl}/track?id=${emergencyId}`;

    const messageBody = emergencyId === "TEST_SIGNAL" 
      ? `🚨 SAFE-VOICE SYSTEM TEST\nSignal verified for ${userName}.\nEncryption: AES-256\nUplink: STABLE`
      : `🚨 EMERGENCY ALERT\n${userName} is in danger.\n\nTrack live location here:\n${trackingLink}`;

    const dispatchResults = [];
    let sentSuccess = 0;

    // Send to each contact sequentially (simpler for small batches)
    for (const contact of contacts) {
      try {
        // Ensure phone is E.164
        const targetPhone = contact.phone.trim().startsWith('+') 
          ? contact.phone.trim() 
          : `+${contact.phone.trim()}`;

        const message = await client.messages.create({
          body: messageBody,
          from: twilioFrom,
          to: targetPhone,
        });

        dispatchResults.push({ name: contact.name, phone: targetPhone, status: "sent", sid: message.sid });
        sentSuccess++;
      } catch (err: any) {
        console.error(`[Twilio Error] Contact: ${contact.name}, Error: ${err.message}`);
        dispatchResults.push({ name: contact.name, phone: contact.phone, status: "failed", error: err.message });
      }
    }

    return res.status(200).json({
      success: sentSuccess > 0,
      sentCount: sentSuccess,
      totalCount: contacts.length,
      results: dispatchResults,
    });
  } catch (error: any) {
    console.error("[Twilio Critical] System Failure:", error);
    return res.status(500).json({ success: false, error: "Internal Server Error during dispatch." });
  }
}

import React, { useState, useEffect, useRef } from 'react';
import { UserProfile, EmergencyRecord, LocationUpdate } from '../types';
import { firebaseService } from '../firebase';
import { GoogleGenAI } from "@google/genai";

declare const google: any;

interface EmergencyScreenProps {
  user: UserProfile;
  emergency: EmergencyRecord;
  onResolve: () => void;
}

const EmergencyScreen: React.FC<EmergencyScreenProps> = ({ user, emergency, onResolve }) => {
  const [lastUpdate, setLastUpdate] = useState<number>(Date.now());
  const [aiInsight, setAiInsight] = useState<string>("Analyzing local environment...");
  const [mapError, setMapError] = useState<boolean>(false);
  const [dispatchStatus, setDispatchStatus] = useState<{sent: number, total: number} | null>(null);

  const mapRef = useRef<any>(null);
  const markerRef = useRef<any>(null);
  const pathRef = useRef<any>(null);
  const watchIdRef = useRef<number | null>(null);

  useEffect(() => {
    const handleDispatch = (e: any) => {
      const data = e.detail;
      if (data.sentCount !== undefined) {
        setDispatchStatus({ sent: data.sentCount, total: data.totalCount || 0 });
      }
    };
    window.addEventListener('twilio_dispatch_result', handleDispatch);
    return () => window.removeEventListener('twilio_dispatch_result', handleDispatch);
  }, []);

  useEffect(() => {
    const initMap = async () => {
      if (typeof google === 'undefined' || !google.maps || !google.maps.importLibrary) {
        setMapError(true);
        return;
      }

      try {
        const { Map } = await google.maps.importLibrary("maps");
        mapRef.current = new Map(document.getElementById("google-map"), {
          center: { lat: 0, lng: 0 },
          zoom: 18,
          disableDefaultUI: true,
          styles: [
            { elementType: "geometry", stylers: [{ color: "#242f3e" }] },
            { elementType: "labels.text.stroke", stylers: [{ color: "#242f3e" }] },
            { elementType: "labels.text.fill", stylers: [{ color: "#746855" }] },
          ]
        });

        pathRef.current = new google.maps.Polyline({
          strokeColor: "#D32F2F",
          strokeOpacity: 0.8,
          strokeWeight: 4,
          map: mapRef.current
        });
      } catch (err) {
        setMapError(true);
      }
    };

    initMap();

    if ("geolocation" in navigator) {
      watchIdRef.current = navigator.geolocation.watchPosition(
        (pos) => {
          const { latitude, longitude } = pos.coords;
          const update: LocationUpdate = {
            emergencyId: emergency.emergencyId,
            latitude,
            longitude,
            timestamp: Date.now()
          };

          firebaseService.pushLocation(update);
          setLastUpdate(Date.now());

          if (mapRef.current) {
            const latLng = { lat: latitude, lng: longitude };
            mapRef.current.setCenter(latLng);

            if (!markerRef.current) {
              markerRef.current = new google.maps.Marker({
                position: latLng,
                map: mapRef.current,
                icon: {
                  path: google.maps.SymbolPath.CIRCLE,
                  scale: 10,
                  fillColor: "#D32F2F",
                  fillOpacity: 1,
                  strokeColor: "#FFFFFF",
                  strokeWeight: 2,
                }
              });
            } else {
              markerRef.current.setPosition(latLng);
            }

            if (pathRef.current) {
              const path = pathRef.current.getPath();
              path.push(new google.maps.LatLng(latitude, longitude));
            }
          }
        },
        (err) => console.error("GPS Error:", err),
        { enableHighAccuracy: true, timeout: 5000, maximumAge: 0 }
      );
    }

    return () => {
      if (watchIdRef.current) navigator.geolocation.clearWatch(watchIdRef.current);
    };
  }, [emergency.emergencyId]);

  useEffect(() => {
    const fetchAiAdvice = async () => {
      if (!process.env.API_KEY) return;
      try {
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
        const response = await ai.models.generateContent({
          model: 'gemini-3-flash-preview',
          contents: "Provide a very short tactical safety tip (10 words max) for someone in immediate danger. For example: 'Stay in lit areas' or 'Find a safe exit'."
        });
        setAiInsight(response.text || "Scanning perimeter. Stay alert.");
      } catch (e) {
        setAiInsight("Protocol active. Move toward safety.");
      }
    };
    fetchAiAdvice();
    const interval = setInterval(fetchAiAdvice, 20000);
    return () => clearInterval(interval);
  }, []);

  return (
    <div className="relative h-full w-full bg-black overflow-hidden">
      <div id="google-map" className="absolute inset-0 z-0 opacity-70">
        {mapError && (
          <div className="h-full w-full flex flex-col items-center justify-center bg-[#090b0e] p-8 text-center">
             <i className="fa-solid fa-map-location-dot text-gray-800 text-6xl mb-6"></i>
             <p className="text-gray-500 font-black uppercase text-[10px] tracking-widest leading-relaxed">Map Feed Interrupted</p>
          </div>
        )}
      </div>

      <div className="absolute top-10 left-4 right-4 z-10 space-y-3 pointer-events-none">
        <div className="bg-black/80 backdrop-blur-xl border border-white/10 rounded-2xl p-4 shadow-2xl pointer-events-auto">
          <div className="flex justify-between items-center mb-2">
            <div className="flex items-center gap-2">
              <div className="w-2 h-2 rounded-full bg-red-500 animate-ping"></div>
              <h2 className="text-[10px] font-black tracking-widest text-red-500 uppercase">Tactical Advice</h2>
            </div>
            <span className="text-[8px] font-mono text-gray-500 uppercase">Real-time Feed</span>
          </div>
          <p className="text-white text-xs font-bold leading-relaxed italic">"{aiInsight}"</p>
        </div>

        {/* SOS Dispatch Status HUD */}
        <div className="bg-black/80 backdrop-blur-xl border border-white/10 rounded-2xl p-3 shadow-2xl pointer-events-auto flex items-center justify-between">
           <div className="flex items-center gap-3">
              <i className="fa-solid fa-tower-broadcast text-blue-500 text-xs"></i>
              <span className="text-[9px] font-black uppercase text-gray-400">SMS Dispatch:</span>
           </div>
           {dispatchStatus ? (
             <span className={`text-[10px] font-black font-mono ${dispatchStatus.sent > 0 ? 'text-green-500' : 'text-red-500'}`}>
               {dispatchStatus.sent}/{dispatchStatus.total} SUCCESS
             </span>
           ) : (
             <div className="flex items-center gap-2">
                <span className="text-[9px] font-black font-mono text-yellow-500 uppercase animate-pulse">Broadcasting...</span>
             </div>
           )}
        </div>
      </div>

      <div className="absolute bottom-10 left-6 right-6 z-20">
        <div className="bg-black/80 backdrop-blur-2xl border border-white/10 rounded-[2.5rem] p-6 shadow-[0_30px_60px_rgba(0,0,0,0.8)]">
          <div className="flex items-center justify-between mb-6 px-2">
             <div>
               <p className="text-[8px] text-gray-500 font-black uppercase mb-1">Operative</p>
               <h4 className="text-white text-sm font-black uppercase tracking-tight">{user.name}</h4>
             </div>
             <div className="text-right">
                <p className="text-[8px] text-gray-500 font-black uppercase mb-1">Signal Quality</p>
                <div className="flex gap-0.5 items-end h-3">
                   <div className="w-1 h-1 bg-emerald-500"></div>
                   <div className="w-1 h-2 bg-emerald-500"></div>
                   <div className="w-1 h-3 bg-emerald-500"></div>
                   <div className="w-1 h-2.5 bg-gray-700"></div>
                </div>
             </div>
          </div>

          <button 
            onClick={onResolve}
            className="w-full bg-[#10B981] hover:bg-emerald-400 text-white py-5 rounded-[1.5rem] font-black text-xs tracking-[0.2em] shadow-2xl active:scale-95 transition-all uppercase"
          >
            I am safe / Terminate Session
          </button>
        </div>
      </div>
    </div>
  );
};

export default EmergencyScreen;
